fn merge_prepared_inputs_for_same_measurement_set(
    inputs: Vec<PreparedInput>,
) -> Result<PreparedInput, String> {
    merge_prepared_inputs_with_density_merge(inputs, CasaCubeBriggsDensityMerge::SameMeasurementSet)
}

fn visibility_batches_sample_count(batches: &[VisibilityBatch]) -> usize {
    batches.iter().map(VisibilityBatch::len).sum()
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct PreparedCubeBatchStats {
    visibility_batches: usize,
    visibility_samples: usize,
    visibility_capacity: usize,
    density_batches: usize,
    density_samples: usize,
    density_capacity: usize,
    model_batches: usize,
    model_samples: usize,
    model_capacity: usize,
}

impl PreparedCubeBatchStats {
    fn add(&mut self, extra: Self) {
        self.visibility_batches = self
            .visibility_batches
            .saturating_add(extra.visibility_batches);
        self.visibility_samples = self
            .visibility_samples
            .saturating_add(extra.visibility_samples);
        self.visibility_capacity = self
            .visibility_capacity
            .saturating_add(extra.visibility_capacity);
        self.density_batches = self.density_batches.saturating_add(extra.density_batches);
        self.density_samples = self.density_samples.saturating_add(extra.density_samples);
        self.density_capacity = self.density_capacity.saturating_add(extra.density_capacity);
        self.model_batches = self.model_batches.saturating_add(extra.model_batches);
        self.model_samples = self.model_samples.saturating_add(extra.model_samples);
        self.model_capacity = self.model_capacity.saturating_add(extra.model_capacity);
    }

    fn visibility_capacity_surplus(self) -> usize {
        self.visibility_capacity
            .saturating_sub(self.visibility_samples)
    }

    fn density_capacity_surplus(self) -> usize {
        self.density_capacity.saturating_sub(self.density_samples)
    }

    fn model_capacity_surplus(self) -> usize {
        self.model_capacity.saturating_sub(self.model_samples)
    }
}

fn visibility_batch_capacity(batches: &[VisibilityBatch]) -> usize {
    batches.iter().map(|batch| batch.u_lambda.capacity()).sum()
}

fn model_interpolation_batch_sample_count(batches: &[CubeModelInterpolationBatch]) -> usize {
    batches
        .iter()
        .map(|batch| batch.sample_contributions.len())
        .sum()
}

fn model_interpolation_batch_capacity(batches: &[CubeModelInterpolationBatch]) -> usize {
    batches
        .iter()
        .map(|batch| batch.sample_contributions.capacity())
        .sum()
}

fn prepared_cube_batch_stats(input: &PreparedInput) -> PreparedCubeBatchStats {
    let PreparedInput::Cube(cube) = input else {
        return PreparedCubeBatchStats::default();
    };
    let mut stats = PreparedCubeBatchStats::default();
    for channel in &cube.channels {
        stats.visibility_batches = stats
            .visibility_batches
            .saturating_add(channel.visibility_batches.len());
        stats.visibility_samples = stats
            .visibility_samples
            .saturating_add(visibility_batches_sample_count(&channel.visibility_batches));
        stats.visibility_capacity = stats
            .visibility_capacity
            .saturating_add(visibility_batch_capacity(&channel.visibility_batches));
        stats.density_batches = stats
            .density_batches
            .saturating_add(channel.density_batches.len());
        stats.density_samples = stats
            .density_samples
            .saturating_add(visibility_batches_sample_count(&channel.density_batches));
        stats.density_capacity = stats
            .density_capacity
            .saturating_add(visibility_batch_capacity(&channel.density_batches));
        stats.model_batches = stats
            .model_batches
            .saturating_add(channel.model_interpolation_batches.len());
        stats.model_samples =
            stats
                .model_samples
                .saturating_add(model_interpolation_batch_sample_count(
                    &channel.model_interpolation_batches,
                ));
        stats.model_capacity =
            stats
                .model_capacity
                .saturating_add(model_interpolation_batch_capacity(
                    &channel.model_interpolation_batches,
                ));
    }
    stats
}

fn merge_prepared_inputs_with_density_merge(
    mut inputs: Vec<PreparedInput>,
    density_merge: CasaCubeBriggsDensityMerge,
) -> Result<PreparedInput, String> {
    if inputs.is_empty() {
        return Err("multi-MS imaging resolved to no prepared inputs".to_string());
    }
    let first = inputs.remove(0);
    let PreparedInput::Mfs(mut merged_plane) = first else {
        let mut merged = first;
        for input in inputs {
            merged = merge_two_prepared_inputs(merged, input, density_merge)?;
        }
        return Ok(merged);
    };

    let mut sample_frequency_range_hz = merged_plane.sample_frequency_range_hz;
    for input in inputs {
        let PreparedInput::Mfs(mut plane) = input else {
            return Err("multi-MS inputs resolved to mixed MFS and cube products".to_string());
        };
        ensure_same_phase_center(&merged_plane.phase_center, &plane.phase_center)?;
        let can_merge_by_sample_frequencies = !merged_plane.sample_frequency_batches_hz.is_empty()
            && !plane.sample_frequency_batches_hz.is_empty();
        if merged_plane.freq_ref != plane.freq_ref && !can_merge_by_sample_frequencies {
            return Err(format!(
                "multi-MS MFS inputs use different frequency frames: {:?} versus {:?}",
                merged_plane.freq_ref, plane.freq_ref
            ));
        }
        if merged_plane.plane_stokes != plane.plane_stokes {
            return Err(format!(
                "multi-MS MFS inputs use different imaging planes: {:?} versus {:?}",
                merged_plane.plane_stokes, plane.plane_stokes
            ));
        }
        merged_plane.gridder_mode = merge_gridder_modes(
            merged_plane.gridder_mode,
            plane.gridder_mode,
            merged_plane.batches.len(),
            plane.batches.len(),
            visibility_batches_sample_count(&merged_plane.batches),
            visibility_batches_sample_count(&plane.batches),
        )?;
        merged_plane.selected_frequency_range_hz = [
            merged_plane.selected_frequency_range_hz[0].min(plane.selected_frequency_range_hz[0]),
            merged_plane.selected_frequency_range_hz[1].max(plane.selected_frequency_range_hz[1]),
        ];
        merged_plane.spectral_frequency_edge_range_hz = merge_optional_frequency_ranges(
            merged_plane.spectral_frequency_edge_range_hz,
            plane.spectral_frequency_edge_range_hz,
        );
        if let Some(plane_sample_frequency_range_hz) = plane.sample_frequency_range_hz {
            extend_frequency_range_hz(
                &mut sample_frequency_range_hz,
                plane_sample_frequency_range_hz,
            );
        }
        if let Some(range) = sample_frequency_range_hz {
            merged_plane.selected_frequency_range_hz = range;
            merged_plane.freq_ref = FrequencyRef::LSRK;
            if let Some(edge_range) = merged_plane.spectral_frequency_edge_range_hz {
                let edge_delta = edge_range[1] - edge_range[0];
                let center = 0.5
                    * (merged_plane.selected_frequency_range_hz[0]
                        + merged_plane.selected_frequency_range_hz[1]);
                merged_plane.spectral_frequency_edge_range_hz =
                    Some([center - 0.5 * edge_delta, center + 0.5 * edge_delta]);
            }
        }
        merged_plane.reffreq_hz = 0.5
            * (merged_plane.selected_frequency_range_hz[0]
                + merged_plane.selected_frequency_range_hz[1]);
        merged_plane.batches.append(&mut plane.batches);
        merged_plane
            .sample_frequency_batches_hz
            .append(&mut plane.sample_frequency_batches_hz);
    }
    Ok(PreparedInput::Mfs(merged_plane))
}

fn merge_two_prepared_inputs(
    left: PreparedInput,
    right: PreparedInput,
    density_merge: CasaCubeBriggsDensityMerge,
) -> Result<PreparedInput, String> {
    match (left, right) {
        (PreparedInput::Mfs(mut left), PreparedInput::Mfs(right)) => {
            ensure_same_phase_center(&left.phase_center, &right.phase_center)?;
            let can_merge_by_sample_frequencies = !left.sample_frequency_batches_hz.is_empty()
                && !right.sample_frequency_batches_hz.is_empty();
            if left.freq_ref != right.freq_ref && !can_merge_by_sample_frequencies {
                return Err(format!(
                    "multi-MS MFS inputs use different frequency frames: {:?} versus {:?}",
                    left.freq_ref, right.freq_ref
                ));
            }
            if left.plane_stokes != right.plane_stokes {
                return Err(format!(
                    "multi-MS MFS inputs use different imaging planes: {:?} versus {:?}",
                    left.plane_stokes, right.plane_stokes
                ));
            }
            left.gridder_mode = merge_gridder_modes(
                left.gridder_mode,
                right.gridder_mode,
                left.batches.len(),
                right.batches.len(),
                visibility_batches_sample_count(&left.batches),
                visibility_batches_sample_count(&right.batches),
            )?;
            left.selected_frequency_range_hz = [
                left.selected_frequency_range_hz[0].min(right.selected_frequency_range_hz[0]),
                left.selected_frequency_range_hz[1].max(right.selected_frequency_range_hz[1]),
            ];
            left.spectral_frequency_edge_range_hz = merge_optional_frequency_ranges(
                left.spectral_frequency_edge_range_hz,
                right.spectral_frequency_edge_range_hz,
            );
            if let Some(range) = sample_frequency_batch_range_hz(
                left.sample_frequency_batches_hz
                    .iter()
                    .chain(right.sample_frequency_batches_hz.iter()),
            )? {
                left.selected_frequency_range_hz = range;
                left.freq_ref = FrequencyRef::LSRK;
                if let Some(edge_range) = left.spectral_frequency_edge_range_hz {
                    let edge_delta = edge_range[1] - edge_range[0];
                    let center = 0.5
                        * (left.selected_frequency_range_hz[0]
                            + left.selected_frequency_range_hz[1]);
                    left.spectral_frequency_edge_range_hz =
                        Some([center - 0.5 * edge_delta, center + 0.5 * edge_delta]);
                }
            }
            left.reffreq_hz =
                0.5 * (left.selected_frequency_range_hz[0] + left.selected_frequency_range_hz[1]);
            left.batches.extend(right.batches);
            left.sample_frequency_batches_hz
                .extend(right.sample_frequency_batches_hz);
            Ok(PreparedInput::Mfs(left))
        }
        (PreparedInput::Cube(mut left), PreparedInput::Cube(right)) => {
            ensure_same_phase_center(&left.phase_center, &right.phase_center)?;
            if left.freq_ref != right.freq_ref {
                return Err(format!(
                    "multi-MS cube inputs use different frequency frames: {:?} versus {:?}",
                    left.freq_ref, right.freq_ref
                ));
            }
            if left.plane_stokes != right.plane_stokes {
                return Err(format!(
                    "multi-MS cube inputs use different imaging planes: {:?} versus {:?}",
                    left.plane_stokes, right.plane_stokes
                ));
            }
            if left.channels.len() != right.channels.len() {
                return Err(format!(
                    "multi-MS cube inputs resolved to different channel counts: {} versus {}",
                    left.channels.len(),
                    right.channels.len()
                ));
            }
            if left.gridder_modes.len() != right.gridder_modes.len() {
                return Err(format!(
                    "multi-MS cube inputs resolved to different gridder-mode counts: {} versus {}",
                    left.gridder_modes.len(),
                    right.gridder_modes.len()
                ));
            }
            left.casa_cube_briggs_preweighting = merge_casa_cube_briggs_preweighting(
                left.casa_cube_briggs_preweighting,
                right.casa_cube_briggs_preweighting,
                density_merge,
            )?;
            let left_visibility_batch_counts = left
                .channels
                .iter()
                .map(|channel| channel.visibility_batches.len())
                .collect::<Vec<_>>();
            let right_visibility_batch_counts = right
                .channels
                .iter()
                .map(|channel| channel.visibility_batches.len())
                .collect::<Vec<_>>();
            let left_visibility_sample_counts = left
                .channels
                .iter()
                .map(|channel| visibility_batches_sample_count(&channel.visibility_batches))
                .collect::<Vec<_>>();
            let right_visibility_sample_counts = right
                .channels
                .iter()
                .map(|channel| visibility_batches_sample_count(&channel.visibility_batches))
                .collect::<Vec<_>>();
            for (gridder_index, (left_mode, right_mode)) in left
                .gridder_modes
                .iter_mut()
                .zip(right.gridder_modes)
                .enumerate()
            {
                *left_mode = merge_gridder_modes(
                    left_mode.clone(),
                    right_mode,
                    left_visibility_batch_counts[gridder_index],
                    right_visibility_batch_counts[gridder_index],
                    left_visibility_sample_counts[gridder_index],
                    right_visibility_sample_counts[gridder_index],
                )?;
            }
            for (channel_index, (left_channel, right_channel)) in
                left.channels.iter_mut().zip(right.channels).enumerate()
            {
                if !frequencies_close(
                    left_channel.channel_frequency_hz,
                    right_channel.channel_frequency_hz,
                ) {
                    return Err(format!(
                        "multi-MS cube channel {channel_index} frequency differs: {} Hz versus {} Hz",
                        left_channel.channel_frequency_hz, right_channel.channel_frequency_hz
                    ));
                }
                left_channel
                    .visibility_batches
                    .extend(right_channel.visibility_batches);
                left_channel
                    .density_batches
                    .extend(right_channel.density_batches);
                left_channel
                    .model_interpolation_batches
                    .extend(right_channel.model_interpolation_batches);
            }
            Ok(PreparedInput::Cube(left))
        }
        (PreparedInput::Mfs(_), PreparedInput::Cube(_))
        | (PreparedInput::Cube(_), PreparedInput::Mfs(_)) => {
            Err("multi-MS inputs resolved to mixed MFS and cube preparations".to_string())
        }
    }
}

fn merge_casa_cube_briggs_preweighting(
    left: Option<CasaCubeBriggsPreparedWeighting>,
    right: Option<CasaCubeBriggsPreparedWeighting>,
    density_merge: CasaCubeBriggsDensityMerge,
) -> Result<Option<CasaCubeBriggsPreparedWeighting>, String> {
    match (left, right) {
        (None, None) => Ok(None),
        (Some(_), None) | (None, Some(_)) => {
            Err("multi-MS cube inputs disagree on CASA cube Briggs preweighting state".to_string())
        }
        (Some(mut left), Some(right)) => {
            if left.weighting != right.weighting {
                return Err(format!(
                    "multi-MS cube Briggs weighting differs: {:?} versus {:?}",
                    left.weighting, right.weighting
                ));
            }
            if !frequencies_close(left.fractional_bandwidth, right.fractional_bandwidth) {
                return Err(format!(
                    "multi-MS cube Briggs fractional bandwidth differs: {:.9e} versus {:.9e}",
                    left.fractional_bandwidth, right.fractional_bandwidth
                ));
            }
            if left.density_plane_count != right.density_plane_count {
                return Err(format!(
                    "multi-MS cube Briggs density-plane count per group differs: {} versus {}",
                    left.density_plane_count, right.density_plane_count
                ));
            }
            if left.channel_density_plane_indices.len() != right.channel_density_plane_indices.len()
            {
                return Err(format!(
                    "multi-MS cube Briggs lookup-channel count differs: {} versus {}",
                    left.channel_density_plane_indices.len(),
                    right.channel_density_plane_indices.len()
                ));
            }
            let mut right_density_index_remap = vec![None; right.density_batches.len()];
            for (right_group_index, right_field_id) in
                right.density_group_field_ids.iter().copied().enumerate()
            {
                let right_group_base = right_group_index * right.density_plane_count;
                let left_group_base = match density_merge {
                    CasaCubeBriggsDensityMerge::SameMeasurementSet => left
                        .density_group_field_ids
                        .iter()
                        .position(|known_field_id| *known_field_id == right_field_id)
                        .map(|group_index| group_index * left.density_plane_count)
                        .unwrap_or_else(|| {
                            let group_index = left.density_group_field_ids.len();
                            left.density_group_field_ids.push(right_field_id);
                            left.density_batches.extend(
                                (0..left.density_plane_count).map(|_| empty_visibility_batch(16)),
                            );
                            left.density_sample_rows
                                .extend((0..left.density_plane_count).map(|_| Vec::new()));
                            group_index * left.density_plane_count
                        }),
                    CasaCubeBriggsDensityMerge::DistinctMeasurementSet => {
                        let group_index = left.density_group_field_ids.len();
                        left.density_group_field_ids.push(right_field_id);
                        left.density_batches.extend(
                            (0..left.density_plane_count).map(|_| empty_visibility_batch(16)),
                        );
                        left.density_sample_rows
                            .extend((0..left.density_plane_count).map(|_| Vec::new()));
                        group_index * left.density_plane_count
                    }
                };
                for plane in 0..right.density_plane_count {
                    let right_index = right_group_base + plane;
                    let left_index = left_group_base + plane;
                    right_density_index_remap[right_index] = Some(left_index);
                }
            }
            for (right_index, right_batch) in right.density_batches.into_iter().enumerate() {
                let Some(left_index) = right_density_index_remap
                    .get(right_index)
                    .copied()
                    .flatten()
                else {
                    continue;
                };
                extend_visibility_batch(&mut left.density_batches[left_index], right_batch);
            }
            for (right_index, right_rows) in right.density_sample_rows.into_iter().enumerate() {
                let Some(left_index) = right_density_index_remap
                    .get(right_index)
                    .copied()
                    .flatten()
                else {
                    continue;
                };
                left.density_sample_rows[left_index].extend(right_rows);
            }
            for (left_indices, right_indices) in left
                .channel_density_plane_indices
                .iter_mut()
                .zip(right.channel_density_plane_indices)
            {
                left_indices.extend(right_indices.into_iter().map(|index| {
                    index.and_then(|index| right_density_index_remap.get(index).copied().flatten())
                }));
            }
            for (left_rows, right_rows) in left
                .channel_sample_rows
                .iter_mut()
                .zip(right.channel_sample_rows)
            {
                left_rows.extend(right_rows);
            }
            for (left_channels, right_channels) in left
                .channel_sample_source_channels
                .iter_mut()
                .zip(right.channel_sample_source_channels)
            {
                left_channels.extend(right_channels);
            }
            Ok(Some(left))
        }
    }
}

fn extend_visibility_batch(left: &mut VisibilityBatch, right: VisibilityBatch) {
    left.u_lambda.extend(right.u_lambda);
    left.v_lambda.extend(right.v_lambda);
    left.w_lambda.extend(right.w_lambda);
    left.weight.extend(right.weight);
    left.sumwt_factor.extend(right.sumwt_factor);
    left.gridable.extend(right.gridable);
    left.visibility.extend(right.visibility);
}

fn casa_cube_briggs_density_group_base(
    preweighting: &mut CasaCubeBriggsPreparedWeighting,
    field_id: usize,
) -> usize {
    if let Some(group_index) = preweighting
        .density_group_field_ids
        .iter()
        .position(|known_field_id| *known_field_id == field_id)
    {
        return group_index * preweighting.density_plane_count;
    }

    let group_index = preweighting.density_group_field_ids.len();
    preweighting.density_group_field_ids.push(field_id);
    preweighting
        .density_batches
        .extend((0..preweighting.density_plane_count).map(|_| empty_visibility_batch(16)));
    preweighting
        .density_sample_rows
        .extend((0..preweighting.density_plane_count).map(|_| Vec::new()));
    group_index * preweighting.density_plane_count
}

fn casa_cube_briggs_density_plane_index(
    preweighting: &CasaCubeBriggsPreparedWeighting,
    group_base: usize,
    output_channel: usize,
) -> Option<usize> {
    (output_channel < preweighting.density_plane_count)
        .then_some(group_base + output_channel)
        .filter(|index| *index < preweighting.density_batches.len())
}

fn merge_gridder_modes(
    left: GridderMode,
    right: GridderMode,
    left_batch_count: usize,
    right_batch_count: usize,
    left_sample_count: usize,
    right_sample_count: usize,
) -> Result<GridderMode, String> {
    match (left, right) {
        (GridderMode::Standard, GridderMode::Standard) => Ok(GridderMode::Standard),
        (GridderMode::Mosaic(mut left), GridderMode::Mosaic(right)) => {
            if left.phase_center_direction_rad != right.phase_center_direction_rad
                || left.pb_limit != right.pb_limit
            {
                return Err(
                    "multi-MS mosaic inputs resolved to incompatible gridder metadata".to_string(),
                );
            }
            let left_uses_grouped = !left.grouped_metadata_batches.is_empty();
            let right_uses_grouped = !right.grouped_metadata_batches.is_empty();
            let left_metadata_count = if left_uses_grouped {
                left.grouped_metadata_batches.len()
            } else {
                left.metadata_batches.len()
            };
            let right_metadata_count = if right_uses_grouped {
                right.grouped_metadata_batches.len()
            } else {
                right.metadata_batches.len()
            };
            if left_metadata_count == 0 && left_sample_count == 0 {
                return Ok(GridderMode::Mosaic(right));
            }
            if right_metadata_count == 0 && right_sample_count == 0 {
                return Ok(GridderMode::Mosaic(left));
            }
            if left_uses_grouped != right_uses_grouped {
                return Err(
                    "multi-MS mosaic inputs resolved to mixed expanded and grouped metadata"
                        .to_string(),
                );
            }
            if left_metadata_count != left_batch_count {
                return Err(format!(
                    "left mosaic metadata batch count {} does not match visibility batch count {left_batch_count}",
                    left_metadata_count
                ));
            }
            if right_metadata_count != right_batch_count {
                return Err(format!(
                    "right mosaic metadata batch count {} does not match visibility batch count {right_batch_count}",
                    right_metadata_count
                ));
            }
            if left_uses_grouped {
                left.grouped_metadata_batches
                    .extend(right.grouped_metadata_batches);
            } else {
                left.metadata_batches.extend(right.metadata_batches);
            }
            Ok(GridderMode::Mosaic(left))
        }
        (GridderMode::Standard, GridderMode::Mosaic(_))
        | (GridderMode::Mosaic(_), GridderMode::Standard) => {
            Err("multi-MS inputs resolved to mixed standard and mosaic gridders".to_string())
        }
    }
}

fn ensure_same_phase_center(left: &PhaseCenter, right: &PhaseCenter) -> Result<(), String> {
    if left.reference != right.reference
        || !angles_close(left.angles_rad[0], right.angles_rad[0])
        || !angles_close(left.angles_rad[1], right.angles_rad[1])
    {
        return Err(format!(
            "multi-MS inputs resolved to different phase centers: {:?} versus {:?}",
            left, right
        ));
    }
    Ok(())
}

fn angles_close(left: f64, right: f64) -> bool {
    (left - right).abs() <= 1.0e-12
}

fn frequencies_close(left: f64, right: f64) -> bool {
    let scale = left.abs().max(right.abs()).max(1.0);
    (left - right).abs() <= scale * 1.0e-10
}

fn spectral_delta_from_range(range_hz: [f64; 2]) -> Option<f64> {
    let delta_hz = range_hz[1] - range_hz[0];
    if delta_hz.is_finite() && delta_hz.abs() > 0.0 {
        Some(delta_hz)
    } else {
        None
    }
}

fn merge_optional_frequency_ranges(
    left: Option<[f64; 2]>,
    right: Option<[f64; 2]>,
) -> Option<[f64; 2]> {
    match (left, right) {
        (Some(left), Some(right)) => Some([left[0].min(right[0]), left[1].max(right[1])]),
        (Some(range), None) | (None, Some(range)) => Some(range),
        (None, None) => None,
    }
}

#[allow(dead_code)]
enum RunProducts {
    Mfs(casa_imaging::ImagingResult),
    Mtmfs(MtmfsRunProducts),
    Cube(CubeRunProducts),
}

#[allow(dead_code)]
struct MtmfsRunProducts {
    result: casa_imaging::MtmfsResult,
    primary_beam_weight_samples: Vec<PrimaryBeamWeightSample>,
    spectral_delta_hz: Option<f64>,
}

struct CubeRunProducts {
    result: casa_imaging::CubeImagingResult,
    mosaic_weight: Option<Array4<f32>>,
    coordinate_freq_ref: Option<FrequencyRef>,
    spectral_delta_hz: Option<f64>,
    rest_frequency_hz: Option<f64>,
}

impl RunProducts {
    fn plane_stokes(&self) -> PlaneStokes {
        match self {
            Self::Mfs(result) => result.compatibility.plane_stokes,
            Self::Mtmfs(products) => products.result.compatibility.plane_stokes,
            Self::Cube(products) => products.result.compatibility.plane_stokes,
        }
    }

    fn channel_frequencies_hz(&self) -> &[f64] {
        match self {
            Self::Mfs(result) => &result.compatibility.channel_frequencies_hz,
            Self::Mtmfs(products) => &products.result.compatibility.channel_frequencies_hz,
            Self::Cube(products) => &products.result.compatibility.channel_frequencies_hz,
        }
    }

    fn spectral_delta_hz(&self) -> Option<f64> {
        match self {
            Self::Mfs(_) => None,
            Self::Mtmfs(products) => products.spectral_delta_hz,
            Self::Cube(products) => products.spectral_delta_hz,
        }
    }

    fn coordinate_freq_ref(&self, default: FrequencyRef) -> FrequencyRef {
        match self {
            Self::Cube(products) => products.coordinate_freq_ref.unwrap_or(default),
            Self::Mfs(_) | Self::Mtmfs(_) => default,
        }
    }

    fn rest_frequency_hz(&self) -> Option<f64> {
        match self {
            Self::Cube(products) => products.rest_frequency_hz,
            Self::Mfs(_) | Self::Mtmfs(_) => None,
        }
    }

    fn warnings(&self) -> Vec<String> {
        match self {
            Self::Mfs(result) => result.diagnostics.warnings.clone(),
            Self::Mtmfs(products) => products.result.diagnostics.warnings.clone(),
            Self::Cube(products) => products.result.diagnostics.warnings.clone(),
        }
    }

    fn gridded_samples(&self) -> usize {
        match self {
            Self::Mfs(result) => result.diagnostics.gridded_samples,
            Self::Mtmfs(products) => products.result.diagnostics.gridded_samples,
            Self::Cube(products) => products.result.diagnostics.gridded_samples,
        }
    }

    fn major_cycles(&self) -> usize {
        match self {
            Self::Mfs(result) => result.diagnostics.major_cycles,
            Self::Mtmfs(products) => products.result.diagnostics.major_cycles,
            Self::Cube(products) => products.result.diagnostics.major_cycles,
        }
    }

    fn minor_iterations(&self) -> usize {
        match self {
            Self::Mfs(result) => result.diagnostics.minor_iterations,
            Self::Mtmfs(products) => products.result.diagnostics.minor_iterations,
            Self::Cube(products) => products.result.diagnostics.minor_iterations,
        }
    }

    fn clean_stop_reason(&self) -> Option<CleanStopReason> {
        match self {
            Self::Mfs(result) => result.diagnostics.clean_stop_reason,
            Self::Mtmfs(products) => products.result.diagnostics.clean_stop_reason,
            Self::Cube(products) => products.result.diagnostics.clean_stop_reason,
        }
    }

    fn minor_cycle_traces(&self) -> Vec<MinorCycleTrace> {
        match self {
            Self::Mfs(result) => result.diagnostics.minor_cycle_traces.clone(),
            Self::Mtmfs(products) => products.result.diagnostics.minor_cycle_traces.clone(),
            Self::Cube(_) => Vec::new(),
        }
    }

    fn channel_summaries(&self) -> Vec<ChannelRunSummary> {
        match self {
            Self::Mfs(_) => Vec::new(),
            Self::Mtmfs(_) => Vec::new(),
            Self::Cube(products) => products
                .result
                .diagnostics
                .channel_diagnostics
                .iter()
                .enumerate()
                .map(|(channel_index, diag)| ChannelRunSummary {
                    channel_index,
                    major_cycles: diag.major_cycles,
                    minor_iterations: diag.minor_iterations,
                    clean_stop_reason: diag.clean_stop_reason,
                    initial_residual_peak_jy_per_beam: diag.initial_residual_peak_jy_per_beam,
                    final_residual_peak_jy_per_beam: diag.final_residual_peak_jy_per_beam,
                    final_cycle_threshold_jy_per_beam: diag.final_cycle_threshold_jy_per_beam,
                    minor_cycle_traces: diag.minor_cycle_traces.clone(),
                    beam_fit_debug: diag.beam_fit_debug.clone(),
                })
                .collect(),
        }
    }

    fn stage_timings(&self) -> ImagingStageTimings {
        match self {
            Self::Mfs(result) => result.diagnostics.stage_timings,
            Self::Mtmfs(products) => products.result.diagnostics.stage_timings,
            Self::Cube(products) => products.result.diagnostics.stage_timings,
        }
    }
}

fn trace_casa_cube_briggs_row(row: Option<usize>) -> bool {
    let Some(row) = row else {
        return false;
    };
    match std::env::var("CASA_RS_TRACE_CUBE_BRIGGS_ROW") {
        Ok(value) if value == "all" => true,
        Ok(value) => value
            .split([',', ';', ' ', '\n', '\t'])
            .filter_map(|part| part.trim().parse::<usize>().ok())
            .any(|target| target == row),
        Err(_) => matches!(
            row,
            31 | 36 | 44 | 46 | 50 | 53 | 74 | 1675 | 1680 | 1688 | 1690 | 1694 | 1697
        ),
    }
}

fn trace_m100_row(row: usize) -> bool {
    static FILTER: OnceLock<TraceRowFilter> = OnceLock::new();
    FILTER
        .get_or_init(|| TraceRowFilter::from_env("CASA_RS_TRACE_M100_ROW0"))
        .contains(row)
}

enum TraceRowFilter {
    Disabled,
    All,
    Rows(Vec<usize>),
}

impl TraceRowFilter {
    fn from_env(name: &str) -> Self {
        match std::env::var(name) {
            Ok(value) if value == "all" => Self::All,
            Ok(value) => {
                let rows = value
                    .split([',', ';', ' ', '\n', '\t'])
                    .filter_map(|part| part.trim().parse::<usize>().ok())
                    .collect::<Vec<_>>();
                if rows.is_empty() {
                    Self::Disabled
                } else {
                    Self::Rows(rows)
                }
            }
            Err(_) => Self::Disabled,
        }
    }

    fn contains(&self, row: usize) -> bool {
        match self {
            Self::Disabled => false,
            Self::All => true,
            Self::Rows(rows) => rows.contains(&row),
        }
    }
}

struct CasaCubeBriggsDensityGridSet {
    weighting: WeightingMode,
    fractional_bandwidth: f64,
    density_plane_count: usize,
    density_group_field_ids: Vec<usize>,
    density_grids: Vec<Array2<f32>>,
    f2_by_plane: Vec<f32>,
}

impl CasaCubeBriggsDensityGridSet {
    fn new_from_direct(geometry: ImageGeometry, plan: &MosaicCubeBriggsDirectDensityPlan) -> Self {
        let _ = geometry;
        Self {
            weighting: plan.weighting,
            fractional_bandwidth: plan.fractional_bandwidth,
            density_plane_count: plan.density_plane_count,
            density_group_field_ids: Vec::new(),
            density_grids: Vec::new(),
            f2_by_plane: Vec::new(),
        }
    }

    fn ensure_group(&mut self, field_id: usize, shape: (usize, usize)) -> usize {
        if let Some(group_index) = self
            .density_group_field_ids
            .iter()
            .position(|known| *known == field_id)
        {
            return group_index * self.density_plane_count;
        }
        let group_index = self.density_group_field_ids.len();
        self.density_group_field_ids.push(field_id);
        self.density_grids
            .extend((0..self.density_plane_count).map(|_| Array2::<f32>::zeros(shape)));
        group_index * self.density_plane_count
    }

    fn finish(&mut self) {
        self.f2_by_plane = self
            .density_grids
            .iter()
            .map(|density| casa_cube_briggs_f2(self.weighting, density))
            .collect();
    }
}

struct MosaicCubeBriggsDirectDensityPlan {
    weighting: WeightingMode,
    fractional_bandwidth: f64,
    density_plane_count: usize,
    source_channel_indices: Arc<[usize]>,
    source_channel_frequencies_hz: Arc<[f64]>,
    spw_frequencies_hz: Arc<[f64]>,
    spw_widths_hz: Arc<[f64]>,
    output_channel_frequencies_hz: Arc<[f64]>,
    polarization: CubeOneChannelBriggsPolarization,
    pair_transform: Option<PairCollapseTransform>,
    plane_stokes: PlaneStokes,
    phase_center_direction_rad: [f64; 2],
    image_shape: (usize, usize),
    cell_size_rad: [f64; 2],
}

impl MosaicCubeBriggsDirectDensityPlan {
    fn new(
        config: &CliConfig,
        geometry: ImageGeometry,
        preweighting: &CasaCubeBriggsPreparedWeighting,
        table_values: &PreparedSelectionTableValues,
        density_channel_read_range: SelectedChannelReadRange,
        phase_center_direction_rad: [f64; 2],
        output_channel_frequencies_hz: Vec<f64>,
    ) -> Result<Self, String> {
        let explicit_plane = config
            .correlation
            .as_deref()
            .map(parse_plane_stokes)
            .transpose()?;
        let plane_stokes = explicit_plane.unwrap_or(PlaneStokes::I);
        let mut pair_transform = None;
        let polarization = if let Some(corr_code) = plane_to_corr_code(plane_stokes) {
            let corr_index = table_values
                .corr_types
                .iter()
                .position(|code| *code == corr_code)
                .ok_or_else(|| {
                    format!(
                        "requested raw correlation plane {} is not present",
                        plane_stokes.as_str()
                    )
                })?;
            CubeOneChannelBriggsPolarization::Explicit { corr_index }
        } else {
            let (pair, transform) = plane_stokes
                .derive_pair_selection(&table_values.corr_types)
                .map_err(|error| error.to_string())?;
            pair_transform = Some(transform);
            CubeOneChannelBriggsPolarization::CollapsedPair {
                first_corr_index: pair.0,
                second_corr_index: pair.1,
            }
        };
        Ok(Self {
            weighting: preweighting.weighting,
            fractional_bandwidth: preweighting.fractional_bandwidth,
            density_plane_count: preweighting.density_plane_count,
            source_channel_indices: Arc::from(
                (density_channel_read_range.start
                    ..density_channel_read_range.start + density_channel_read_range.count)
                    .collect::<Vec<_>>()
                    .into_boxed_slice(),
            ),
            source_channel_frequencies_hz: Arc::from(
                table_values.spw_freqs_hz[density_channel_read_range.start
                    ..density_channel_read_range.start + density_channel_read_range.count]
                    .to_vec(),
            ),
            spw_frequencies_hz: Arc::from(table_values.spw_freqs_hz.clone()),
            spw_widths_hz: Arc::from(table_values.spw_widths_hz.clone()),
            output_channel_frequencies_hz: Arc::from(output_channel_frequencies_hz),
            polarization,
            pair_transform,
            plane_stokes,
            phase_center_direction_rad,
            image_shape: (geometry.image_shape[0], geometry.image_shape[1]),
            cell_size_rad: geometry.cell_size_rad,
        })
    }
}

fn accumulate_mosaic_cube_briggs_direct_density_rows(
    selected_rows: &[SelectedMainRow],
    rows: &[MsImagingDensityEssentials],
    density_set: &mut CasaCubeBriggsDensityGridSet,
    plan: &MosaicCubeBriggsDirectDensityPlan,
    reusable_plan: Option<&CubeRowSpectralReusablePlan>,
    _derived_engine: Option<&MsCalEngine>,
    accumulate_timings: &mut AccumulateRowTimings,
) -> Result<usize, String> {
    if selected_rows.len() != rows.len() {
        return Err(format!(
            "internal error: selected row count {} differs from density row count {}",
            selected_rows.len(),
            rows.len()
        ));
    }
    let field_parallel_threads = standard_mfs_density_prepare_threads(selected_rows.len());
    if field_parallel_threads > 1 && selected_rows.len() >= 1024 {
        return accumulate_mosaic_cube_briggs_direct_density_rows_by_field(
            selected_rows,
            rows,
            density_set,
            plan,
            reusable_plan,
            accumulate_timings,
        );
    }
    let mut accepted_samples = 0usize;
    for (selected_row, row) in selected_rows.iter().zip(rows.iter()) {
        if row.spw_id != selected_row.spw_id {
            return Err(format!(
                "row {} SPW mismatch: selected row has {}, essentials block has {}",
                selected_row.row_index, selected_row.spw_id, row.spw_id
            ));
        }
        let adapt_started = Instant::now();
        if row.gridable {
            let row_time_mjd_sec = selected_row.time_mjd_seconds.ok_or_else(|| {
                "internal error: missing row time for mosaic cube Briggs density".to_string()
            })?;
            let cache_key = (row_time_mjd_sec.to_bits(), selected_row.field_id);
            let spectral_started = Instant::now();
            let contributions = reusable_plan
                .and_then(|plan| plan.spectral(&cache_key))
                .ok_or_else(|| {
                    "internal error: missing reusable spectral entry for mosaic cube Briggs density"
                        .to_string()
                })?;
            accumulate_timings.cube_spectral_lookup += spectral_started.elapsed();
            let density_row_started = Instant::now();
            accepted_samples =
                accepted_samples.saturating_add(accumulate_mosaic_cube_briggs_direct_density_row(
                    selected_row,
                    row,
                    density_set,
                    plan,
                    &contributions,
                )?);
            accumulate_timings.cube_density_grid_update += density_row_started.elapsed();
        }
        accumulate_timings.adapt_samples += adapt_started.elapsed();
    }
    Ok(accepted_samples)
}

fn accumulate_mosaic_cube_briggs_direct_density_rows_by_field(
    selected_rows: &[SelectedMainRow],
    rows: &[MsImagingDensityEssentials],
    density_set: &mut CasaCubeBriggsDensityGridSet,
    plan: &MosaicCubeBriggsDirectDensityPlan,
    reusable_plan: Option<&CubeRowSpectralReusablePlan>,
    accumulate_timings: &mut AccumulateRowTimings,
) -> Result<usize, String> {
    let mut field_ids = BTreeSet::new();
    for (selected_row, row) in selected_rows.iter().zip(rows.iter()) {
        if row.gridable {
            field_ids.insert(selected_row.field_id);
        }
    }
    if field_ids.len() <= 1 {
        let mut accepted_samples = 0usize;
        for (selected_row, row) in selected_rows.iter().zip(rows.iter()) {
            if row.gridable {
                let row_time_mjd_sec = selected_row.time_mjd_seconds.ok_or_else(|| {
                    "internal error: missing row time for mosaic cube Briggs density".to_string()
                })?;
                let cache_key = (row_time_mjd_sec.to_bits(), selected_row.field_id);
                let spectral_started = Instant::now();
                let contributions = reusable_plan
                    .and_then(|plan| plan.spectral(&cache_key))
                    .ok_or_else(|| {
                        "internal error: missing reusable spectral entry for mosaic cube Briggs density"
                            .to_string()
                    })?;
                accumulate_timings.cube_spectral_lookup += spectral_started.elapsed();
                let density_row_started = Instant::now();
                accepted_samples = accepted_samples.saturating_add(
                    accumulate_mosaic_cube_briggs_direct_density_row(
                        selected_row,
                        row,
                        density_set,
                        plan,
                        &contributions,
                    )?,
                );
                accumulate_timings.cube_density_grid_update += density_row_started.elapsed();
            }
        }
        return Ok(accepted_samples);
    }

    for field_id in field_ids {
        density_set.ensure_group(field_id, plan.image_shape);
    }
    let group_by_field = density_set
        .density_group_field_ids
        .iter()
        .copied()
        .enumerate()
        .map(|(group_index, field_id)| (field_id, group_index))
        .collect::<HashMap<_, _>>();
    let mut jobs_by_group = vec![Vec::<usize>::new(); density_set.density_group_field_ids.len()];
    for (index, (selected_row, row)) in selected_rows.iter().zip(rows.iter()).enumerate() {
        if !row.gridable {
            continue;
        }
        let Some(group_index) = group_by_field.get(&selected_row.field_id).copied() else {
            continue;
        };
        jobs_by_group[group_index].push(index);
    }

    let started = Instant::now();
    let mut worker_results = Vec::new();
    let density_plane_count = density_set.density_plane_count;
    let group_field_ids = density_set.density_group_field_ids.clone();
    thread::scope(|scope| {
        let mut handles = Vec::new();
        for (group_index, group_grids) in density_set
            .density_grids
            .chunks_mut(density_plane_count)
            .enumerate()
        {
            let row_indices = &jobs_by_group[group_index];
            if row_indices.is_empty() {
                continue;
            }
            let field_id = group_field_ids[group_index];
            handles.push(scope.spawn(move || {
                let worker_started = Instant::now();
                let mut accepted_samples = 0usize;
                let mut spectral_lookup = Duration::ZERO;
                let mut density_grid_update = Duration::ZERO;
                let mut adapt_samples = Duration::ZERO;
                for &row_index in row_indices {
                    let selected_row = &selected_rows[row_index];
                    let row = &rows[row_index];
                    let adapt_started = Instant::now();
                    let row_time_mjd_sec = selected_row.time_mjd_seconds.ok_or_else(|| {
                        "internal error: missing row time for mosaic cube Briggs density".to_string()
                    })?;
                    let cache_key = (row_time_mjd_sec.to_bits(), selected_row.field_id);
                    let spectral_started = Instant::now();
                    let contributions = reusable_plan
                        .and_then(|plan| plan.spectral(&cache_key))
                        .ok_or_else(|| {
                            "internal error: missing reusable spectral entry for mosaic cube Briggs density"
                                .to_string()
                        })?;
                    spectral_lookup += spectral_started.elapsed();
                    let density_started = Instant::now();
                    accepted_samples = accepted_samples.saturating_add(
                        accumulate_mosaic_cube_briggs_direct_density_row_into_group(
                            selected_row,
                            row,
                            group_grids,
                            plan,
                            &contributions,
                        )?,
                    );
                    density_grid_update += density_started.elapsed();
                    adapt_samples += adapt_started.elapsed();
                }
                Ok::<_, String>((
                    field_id,
                    row_indices.len(),
                    accepted_samples,
                    spectral_lookup,
                    density_grid_update,
                    adapt_samples,
                    worker_started.elapsed(),
                ))
            }));
        }
        for handle in handles {
            worker_results.push(
                handle.join().map_err(|_| {
                    "mosaic cube field-parallel density worker panicked".to_string()
                })??,
            );
        }
        Ok::<(), String>(())
    })?;

    let mut accepted_samples = 0usize;
    let mut worker_rows = Vec::with_capacity(worker_results.len());
    let mut worker_samples = Vec::with_capacity(worker_results.len());
    let mut worker_elapsed = Vec::with_capacity(worker_results.len());
    for (_field_id, rows, samples, spectral_lookup, density_grid_update, adapt_samples, elapsed) in
        worker_results
    {
        accepted_samples = accepted_samples.saturating_add(samples);
        accumulate_timings.cube_spectral_lookup += spectral_lookup;
        accumulate_timings.cube_density_grid_update += density_grid_update;
        accumulate_timings.adapt_samples += adapt_samples;
        worker_rows.push(rows);
        worker_samples.push(samples);
        worker_elapsed.push(duration_ms(elapsed));
    }
    eprintln!(
        "mosaic_cube_density_field_parallel groups={} rows={} samples={} worker_rows={:?} worker_samples={:?} worker_ms={:?} total_ms={:.3}",
        worker_rows.len(),
        selected_rows.len(),
        accepted_samples,
        worker_rows,
        worker_samples,
        worker_elapsed,
        duration_ms(started.elapsed())
    );
    Ok(accepted_samples)
}

fn accumulate_mosaic_cube_briggs_direct_density_row(
    selected_row: &SelectedMainRow,
    row: &MsImagingDensityEssentials,
    density_set: &mut CasaCubeBriggsDensityGridSet,
    plan: &MosaicCubeBriggsDirectDensityPlan,
    contributions: &CubeRowSpectralContributions,
) -> Result<usize, String> {
    let density_group_base = density_set.ensure_group(selected_row.field_id, plan.image_shape);
    let density_group_end = density_group_base + density_set.density_plane_count;
    accumulate_mosaic_cube_briggs_direct_density_row_into_group(
        selected_row,
        row,
        &mut density_set.density_grids[density_group_base..density_group_end],
        plan,
        contributions,
    )
}

fn accumulate_mosaic_cube_briggs_direct_density_row_into_group(
    _selected_row: &SelectedMainRow,
    row: &MsImagingDensityEssentials,
    density_grids: &mut [Array2<f32>],
    plan: &MosaicCubeBriggsDirectDensityPlan,
    contributions: &CubeRowSpectralContributions,
) -> Result<usize, String> {
    let density_uvw_m = gridft_density_uvw_m(
        [row.u_m, row.v_m, row.w_m],
        row.field_phase_center_direction_rad,
        plan.phase_center_direction_rad,
    );
    let mut accepted = 0usize;
    for grid in &contributions.padded_grid_channel_contributions {
        let Some(weight) = cube_one_channel_briggs_density_weight(
            row,
            plan.polarization,
            &plan.source_channel_indices,
            &grid.contributions,
        )?
        else {
            continue;
        };
        if grid.output_channel >= plan.density_plane_count {
            continue;
        }
        let Some(density) = density_grids.get_mut(grid.output_channel) else {
            continue;
        };
        let lambda_scale = grid.grid_frequency_hz / SPEED_OF_LIGHT_M_PER_S;
        let Some((x, y)) = casa_cube_briggs_gridft_density_cell_from_lambda(
            density.dim(),
            density_uvw_m[0] * lambda_scale,
            density_uvw_m[1] * lambda_scale,
            plan.cell_size_rad,
        ) else {
            continue;
        };
        density[(x, y)] += weight;
        let (nx, ny) = density.dim();
        let mirror_x = nx.saturating_sub(x);
        let mirror_y = ny.saturating_sub(y);
        if mirror_x < nx && mirror_y < ny {
            density[(mirror_x, mirror_y)] += weight;
        }
        accepted += 1;
    }
    Ok(accepted)
}

fn cached_direct_mosaic_cube_pb_frequency_hz(
    cache: &mut HashMap<(usize, u64), f64>,
    plan: &MosaicCubeBriggsDirectDensityPlan,
    output_channel: usize,
    output_frequency_hz: f64,
) -> f64 {
    let key = (output_channel, output_frequency_hz.to_bits());
    if let Some(value) = cache.get(&key).copied() {
        return value;
    }
    let value = casa_one_channel_cube_mosaic_pb_frequency_hz(
        output_channel,
        output_frequency_hz,
        Some(plan.output_channel_frequencies_hz.as_ref()),
        plan.source_channel_frequencies_hz.as_ref(),
        plan.spw_frequencies_hz.as_ref(),
        plan.spw_widths_hz.as_ref(),
    );
    cache.insert(key, value);
    value
}

