fn select_main_rows(
    ms: &MeasurementSet,
    config: &CliConfig,
    ddid_info: &[Option<(usize, usize)>],
) -> Result<SelectedRowsContext, String> {
    let select_started_at = Instant::now();
    let needs_pointing_times = config.use_pointing
        && ms
            .pointing()
            .map(|pointing| pointing.row_count() > 0)
            .unwrap_or(false);
    let needs_row_times = matches!(config.spectral_mode, SpectralMode::Mfs)
        || config.spectral_mode.is_cube_like()
        || config.w_term_mode != WTermMode::None
        || selection_may_require_phase_reprojection(config)
        || needs_pointing_times;
    let allowed_ddids = allowed_ddids(config, ddid_info)?;
    let allowed_field_ids = config
        .field_ids
        .as_ref()
        .map(|ids| ids.iter().copied().collect::<BTreeSet<_>>());
    let row_selection = ms
        .select_visibility_rows(&VisibilityRowSelectionRequest::new(
            ddid_info.to_vec(),
            allowed_ddids,
            config.ddid,
            allowed_field_ids,
            needs_row_times,
            config.spectral_mode.is_cube_like(),
        ))
        .map_err(|error| match error {
            casa_ms::MsError::InvalidInput(message) => message,
            other => other.to_string(),
        })?;
    let (
        selected_row_parts,
        selected_ddid,
        selected_fields,
        flag_row,
        reference_row_time_mjd_sec,
        time_bounds_mjd_sec,
    ) = row_selection.into_parts();
    let selected_rows = selected_row_parts
        .iter()
        .map(|row| {
            let (row_index, field_id, ddid, spw_id, polarization_id, time_mjd_seconds) =
                row.parts();
            SelectedMainRow {
                row_index,
                field_id,
                ddid,
                spw_id,
                polarization_id,
                time_mjd_seconds,
            }
        })
        .collect::<Vec<_>>();
    maybe_log_frontend_progress(
        "prepare_plane_input/select_main_rows/scan_rows",
        select_started_at.elapsed(),
        select_started_at.elapsed(),
    );

    let phase_center = resolve_phase_center(ms, &selected_fields, config)?;
    maybe_log_frontend_progress(
        "prepare_plane_input/select_main_rows/resolve_phase_center",
        select_started_at.elapsed(),
        select_started_at.elapsed(),
    );
    let needs_geometry_engine = config.spectral_mode.is_cube_like()
        || config.w_term_mode != WTermMode::None
        || config.phasecenter.is_some()
        || selected_fields
            .iter()
            .copied()
            .any(|field_id| usize::try_from(field_id).ok() != phase_center.field_id);

    Ok(SelectedRowsContext {
        selected_rows,
        selected_ddid,
        phase_center,
        reference_row_time_mjd_sec,
        time_bounds_mjd_sec,
        needs_geometry_engine,
        flag_row,
    })
}

fn load_selected_i32_main_column(
    ms: &MeasurementSet,
    column_name: &'static str,
    row_indices: &[usize],
) -> Result<Vec<i32>, String> {
    let values = ms
        .main_table()
        .column_accessor(column_name)
        .and_then(|column| column.scalar_cells_owned_for_rows(row_indices))
        .map_err(|error| format!("load selected scalar column {column_name}: {error}"))?;
    if values.len() != row_indices.len() {
        return Err(format!(
            "{column_name} selected length {} does not match requested row count {}",
            values.len(),
            row_indices.len()
        ));
    }
    values
        .into_iter()
        .enumerate()
        .map(|(row_slot, value)| match value {
            Some(ScalarValue::Int32(value)) => Ok(value),
            Some(other) => Err(format!(
                "{column_name} selected row slot {row_slot} must be Int32, found {:?}",
                other.primitive_type()
            )),
            None => Err(format!(
                "{column_name} selected row slot {row_slot} is missing"
            )),
        })
        .collect()
}

fn load_selected_optional_i32_main_column(
    ms: &MeasurementSet,
    column_name: &'static str,
    row_indices: &[usize],
) -> Result<Vec<Option<i32>>, String> {
    let Some(column) = ms.main_table().column_accessor(column_name).ok() else {
        return Ok(vec![None; row_indices.len()]);
    };
    let values = column
        .scalar_cells_owned_for_rows(row_indices)
        .map_err(|error| format!("load selected scalar column {column_name}: {error}"))?;
    if values.len() != row_indices.len() {
        return Err(format!(
            "{column_name} selected length {} does not match requested row count {}",
            values.len(),
            row_indices.len()
        ));
    }
    values
        .into_iter()
        .enumerate()
        .map(|(row_slot, value)| match value {
            Some(ScalarValue::Int32(value)) => Ok(Some(value)),
            Some(other) => Err(format!(
                "{column_name} selected row slot {row_slot} must be Int32, found {:?}",
                other.primitive_type()
            )),
            None => Ok(None),
        })
        .collect()
}

fn extract_constant_direction_angles(
    value: &ArrayValue,
    column_name: &str,
    row_index: usize,
) -> Result<[f64; 2], String> {
    match value {
        ArrayValue::Float64(values) => {
            let shape = values.shape();
            if shape.len() != 2 || shape[0] != 2 || shape[1] == 0 {
                return Err(format!(
                    "{column_name} row {row_index} must have shape [2, N], found {shape:?}"
                ));
            }
            Ok([values[[0, 0]], values[[1, 0]]])
        }
        other => Err(format!(
            "{column_name} row {row_index} must be Float64 array, found {:?}",
            other.primitive_type()
        )),
    }
}

fn extract_uvw_from_array(value: &ArrayValue, row_index: usize) -> Result<[f64; 3], String> {
    match value {
        ArrayValue::Float64(values) => {
            let slice = values
                .as_slice()
                .ok_or_else(|| format!("UVW row {row_index} must be contiguous Float64[3] data"))?;
            if slice.len() != 3 {
                return Err(format!(
                    "UVW row {row_index} must have shape [3], found length {}",
                    slice.len()
                ));
            }
            Ok([slice[0], slice[1], slice[2]])
        }
        other => Err(format!(
            "UVW row {row_index} must be Float64 array, found {:?}",
            other.primitive_type()
        )),
    }
}

fn build_prepared_geometry_rows(
    ms: &MeasurementSet,
    selected_rows: &[SelectedMainRow],
    phase_center: &PhaseCenter,
    columns: &PreparedGeometryColumnCache,
    derived_engine: Option<&MsCalEngine>,
    reprojection_mode: UvwReprojectionMode,
) -> Result<Vec<PreparedGeometryRow>, String> {
    let geometry_started_at = Instant::now();
    let selected_row_indices = selected_rows
        .iter()
        .map(|selected_row| selected_row.row_index)
        .collect::<Vec<_>>();
    let geometry = read_visibility_source_geometry_columns(ms, columns, &selected_row_indices)?;
    maybe_log_frontend_progress(
        "prepare_plane_input/build_prepared_geometry_rows/load_selected_uvw",
        geometry.timings.uvw_column,
        geometry_started_at.elapsed(),
    );
    maybe_log_frontend_progress(
        "prepare_plane_input/build_prepared_geometry_rows/load_selected_antenna_ids",
        geometry_started_at.elapsed(),
        geometry_started_at.elapsed(),
    );
    maybe_log_frontend_progress(
        "prepare_plane_input/build_prepared_geometry_rows/load_selected_pointing_ids",
        geometry_started_at.elapsed(),
        geometry_started_at.elapsed(),
    );
    build_prepared_geometry_rows_from_selected_uvw(
        ms,
        selected_rows,
        phase_center,
        columns,
        derived_engine,
        reprojection_mode,
        &geometry.selected_uvw,
        &geometry.antenna1_values,
        &geometry.antenna2_values,
        geometry.pointing_ids.as_deref(),
        geometry_started_at,
    )
}

#[allow(clippy::too_many_arguments)]
fn build_prepared_geometry_rows_from_selected_uvw(
    ms: &MeasurementSet,
    selected_rows: &[SelectedMainRow],
    phase_center: &PhaseCenter,
    columns: &PreparedGeometryColumnCache,
    derived_engine: Option<&MsCalEngine>,
    reprojection_mode: UvwReprojectionMode,
    selected_uvw: &SelectedMainArrayColumn,
    antenna1_values: &[i32],
    antenna2_values: &[i32],
    pointing_ids: Option<&[Option<i32>]>,
    geometry_started_at: Instant,
) -> Result<Vec<PreparedGeometryRow>, String> {
    let mut field_phase_centers = BTreeMap::<usize, [f64; 2]>::new();
    let mut rows = Vec::with_capacity(selected_rows.len());
    for (row_slot, selected_row) in selected_rows.iter().enumerate() {
        let row = selected_row.row_index;
        let antenna1_id = *antenna1_values
            .get(row_slot)
            .ok_or_else(|| format!("read ANTENNA1 row {row}: row is out of bounds"))?;
        let antenna2_id = *antenna2_values
            .get(row_slot)
            .ok_or_else(|| format!("read ANTENNA2 row {row}: row is out of bounds"))?;
        let is_cross = antenna1_id != antenna2_id;
        let raw_uvw_m = extract_uvw_from_array(selected_uvw.get(row_slot)?, row)?;
        let transform = row_imaging_transform(
            row,
            selected_row.field_id,
            phase_center,
            raw_uvw_m,
            derived_engine,
            reprojection_mode,
        )?;
        let row_phase_center =
            if let Some(angles_rad) = field_phase_centers.get(&selected_row.field_id) {
                *angles_rad
            } else {
                let direction = resolve_field_phase_direction_j2000(ms, selected_row.field_id)
                    .map_err(|error| {
                        format!(
                            "resolve FIELD.PHASE_DIR[{}] to J2000 for row {row}: {error}",
                            selected_row.field_id
                        )
                    })?;
                let (ra, dec) = direction.as_angles();
                let angles_rad = [ra, dec];
                field_phase_centers.insert(selected_row.field_id, angles_rad);
                angles_rad
            };
        let antenna1_pointing = match (
            columns.pointing_resolver.as_ref(),
            selected_row.time_mjd_seconds,
        ) {
            (Some(resolver), Some(time_mjd_seconds)) => resolver.resolve(
                pointing_ids
                    .and_then(|values| values.get(row_slot))
                    .copied()
                    .flatten(),
                antenna1_id,
                time_mjd_seconds,
                row_phase_center,
            ),
            (Some(_), None) => {
                return Err(format!(
                    "row {row} requires TIME to resolve POINTING directions"
                ));
            }
            (None, _) => ResolvedPointingDirection {
                source_row_index: None,
                used_fallback: true,
                angles_rad: row_phase_center,
            },
        };
        let antenna2_pointing = match (
            columns.pointing_resolver.as_ref(),
            selected_row.time_mjd_seconds,
        ) {
            (Some(resolver), Some(time_mjd_seconds)) => resolver.resolve(
                pointing_ids
                    .and_then(|values| values.get(row_slot))
                    .copied()
                    .flatten(),
                antenna2_id,
                time_mjd_seconds,
                row_phase_center,
            ),
            (Some(_), None) => {
                return Err(format!(
                    "row {row} requires TIME to resolve POINTING directions"
                ));
            }
            (None, _) => ResolvedPointingDirection {
                source_row_index: None,
                used_fallback: true,
                angles_rad: row_phase_center,
            },
        };
        rows.push(PreparedGeometryRow {
            selected_row: selected_row.clone(),
            phase_center_field_id: phase_center.field_id,
            pointing_id: pointing_ids
                .and_then(|values| values.get(row_slot))
                .copied()
                .flatten(),
            field_phase_center_direction_rad: row_phase_center,
            antenna1_pointing,
            antenna2_pointing,
            antenna1_id,
            antenna2_id,
            is_cross,
            raw_uvw_m,
            transform,
        });
    }
    maybe_log_frontend_progress(
        "prepare_plane_input/build_prepared_geometry_rows/row_loop",
        geometry_started_at.elapsed(),
        geometry_started_at.elapsed(),
    );
    Ok(rows)
}

#[allow(clippy::too_many_arguments)]
fn prepare_processing_buffer(
    ms: &MeasurementSet,
    config: &CliConfig,
    selection: &SelectedRowsContext,
    ddid_info: &[Option<(usize, usize)>],
    spectral_window: &casa_ms::subtables::spectral_window::MsSpectralWindow<'_>,
    polarization: &casa_ms::subtables::polarization::MsPolarization<'_>,
    flag_row: &[bool],
    source_block: &ColumnarPreparedSource,
    derived_engine: Option<&MsCalEngine>,
    accumulate_timings: &mut AccumulateRowTimings,
    mfs_batch_size: usize,
) -> Result<PlaneInput, String> {
    let selected_rows = (0..source_block.row_count())
        .map(|row_slot| source_block.selected_main_row(row_slot))
        .collect::<Result<Vec<_>, _>>()?;
    let block_selection = SelectedRowsContext {
        selected_ddid: selection.selected_ddid,
        selected_rows,
        flag_row: flag_row.to_vec(),
        phase_center: selection.phase_center.clone(),
        needs_geometry_engine: selection.needs_geometry_engine,
        reference_row_time_mjd_sec: selection.reference_row_time_mjd_sec,
        time_bounds_mjd_sec: selection.time_bounds_mjd_sec,
    };
    let cube_context = if config.spectral_mode.is_cube_like()
        && standard_mfs_shared_acceleration_spectral_mode_is_eligible(config)
        && !standard_cube_like_one_channel_can_use_mfs_single_plane_path(config)
    {
        Some(cube_setup_context_for_selection(
            &block_selection,
            derived_engine,
        )?)
    } else {
        None
    };
    let standard_mfs_table_values =
        if standard_cube_like_one_channel_can_use_mfs_single_plane_path(config) {
            Some(load_prepared_selection_table_values(
                selection.selected_ddid,
                ddid_info,
                spectral_window,
                polarization,
            )?)
        } else {
            None
        };
    let finish = if cube_context.is_some() {
        SourceRowBlockFinish::Cube
    } else {
        SourceRowBlockFinish::StandardMfs {
            batch_size: mfs_batch_size,
        }
    };
    let prepared_input = prepare_source_row_block_plane_inner(
        SourceRowBlockPlaneDescriptor {
            ms,
            config,
            selection: &block_selection,
            ddid_info,
            spectral_window,
            polarization,
            source_block,
            flag_row,
            derived_engine,
            standard_mfs_table_values: standard_mfs_table_values.as_ref(),
            cube_context,
            finish,
            cube_row_spectral_reusable_plan: None,
            build_cube_briggs_density_samples: true,
            build_cube_mosaic_metadata: true,
        },
        accumulate_timings,
    )?;
    let plane = match prepared_input {
        PreparedInput::Mfs(plane) => plane,
        PreparedInput::Cube(cube) => standard_one_channel_cube_input_to_plane(cube)?,
    };
    Ok(plane)
}

#[allow(clippy::too_many_arguments)]
fn stream_standard_mfs_density_row_blocks(
    ms: &MeasurementSet,
    config: &CliConfig,
    data_column_kind: VisibilityDataColumn,
    selection: &SelectedRowsContext,
    table_values: &PreparedSelectionTableValues,
    ddid_info: &[Option<(usize, usize)>],
    flag_row: &[bool],
    active_selected_rows: &[SelectedMainRow],
    derived_engine: Option<&MsCalEngine>,
    channel_read_range: Option<SelectedChannelReadRange>,
    geometry_columns: &PreparedGeometryColumnCache,
    row_block_rows: usize,
    prepare_started_at: Instant,
    prepare_stage_timings: &mut PreparePlaneInputStageTimings,
    accumulate_timings: &mut AccumulateRowTimings,
    pass_stats: &mut StandardMfsStreamingPassStats,
    weighting_plan: &mut StandardMfsStreamingWeightingPlan,
) -> Result<usize, String> {
    let mut accepted_samples = 0usize;
    for row_chunk in active_selected_rows.chunks(row_block_rows) {
        let stage_started_at = Instant::now();
        let source_block = read_columnar_prepared_source(
            ms,
            data_column_kind,
            false,
            selection,
            table_values,
            ddid_info,
            row_chunk,
            derived_engine,
            uvw_reprojection_mode_for_selection(config, selection),
            channel_read_range,
            geometry_columns,
            None,
            None,
        )?;
        let mut block_samples = 0usize;
        let get_ms_values_elapsed = stage_started_at.elapsed();
        prepare_stage_timings.get_ms_values_into_processing_buffer += get_ms_values_elapsed;
        pass_stats.add_get_ms_values_detail(source_block.read_timings);

        let stage_started_at = Instant::now();
        let before_accumulate = *accumulate_timings;
        block_samples += accumulate_standard_mfs_density_rows_without_data_parallel(
            config,
            table_values,
            &selection.phase_center,
            &source_block,
            flag_row,
            derived_engine,
            weighting_plan,
            accumulate_timings,
        )?;
        let prepare_processing_elapsed = stage_started_at.elapsed();
        prepare_stage_timings.prepare_processing_buffer += prepare_processing_elapsed;
        pass_stats.add_accumulate_rows_detail(accumulate_timings.delta_since(before_accumulate));
        pass_stats.record_density_block(
            block_samples,
            get_ms_values_elapsed,
            prepare_processing_elapsed,
        );
        accepted_samples += block_samples;
        if frontend_progress_enabled() {
            eprintln!(
                "frontend stage=prepare_plane_input/density_row_block rows_done={} rows_total={} accepted_samples={} total_elapsed_s={:.3}",
                accumulate_timings.rows_seen,
                active_selected_rows.len(),
                accepted_samples,
                prepare_started_at.elapsed().as_secs_f64(),
            );
        }
    }
    Ok(accepted_samples)
}

#[allow(clippy::too_many_arguments)]
fn accumulate_standard_mfs_density_rows_without_data_parallel(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
    phase_center: &PhaseCenter,
    source_block: &ColumnarPreparedSource,
    flag_row: &[bool],
    derived_engine: Option<&MsCalEngine>,
    weighting_plan: &mut StandardMfsStreamingWeightingPlan,
    accumulate_timings: &mut AccumulateRowTimings,
) -> Result<usize, String> {
    let row_count = source_block.row_count();
    let source_view = source_block.source_view()?;
    let thread_count = standard_mfs_density_prepare_threads(row_count);
    if thread_count <= 1 || row_count < 2 {
        let mut prepared = PreparedSelection::new_standard_mfs_from_table_values(
            config,
            table_values,
            phase_center.clone(),
            false,
        )?;
        let mut accepted_samples = 0usize;
        for row_slot in 0..row_count {
            let row = source_block.to_prepared_geometry_row(row_slot);
            accepted_samples += prepared.accumulate_standard_mfs_density_row_without_data(
                &row,
                source_block,
                source_view,
                flag_row,
                derived_engine,
                row_slot,
                weighting_plan,
                accumulate_timings,
            )?;
        }
        return Ok(accepted_samples);
    }

    let started = Instant::now();
    let chunk_len = row_count.div_ceil(thread_count).max(1);
    let row_slots = (0..row_count).collect::<Vec<_>>();
    let plan_template = &*weighting_plan;
    let worker_results = thread::scope(|scope| {
        let mut handles = Vec::with_capacity(thread_count);
        for row_chunk in row_slots.chunks(chunk_len) {
            let table_values = table_values.clone();
            let phase_center = phase_center.clone();
            handles.push(scope.spawn(move || {
                let mut prepared = PreparedSelection::new_standard_mfs_from_table_values(
                    config,
                    &table_values,
                    phase_center,
                    false,
                )?;
                let mut local_plan = plan_template
                    .fork_density_accumulator()
                    .map_err(|error| error.to_string())?;
                let mut local_timings = AccumulateRowTimings::default();
                let mut accepted_samples = 0usize;
                for &row_slot in row_chunk {
                    let row = source_block.to_prepared_geometry_row(row_slot);
                    accepted_samples += prepared.accumulate_standard_mfs_density_row_without_data(
                        &row,
                        source_block,
                        source_view,
                        flag_row,
                        derived_engine,
                        row_slot,
                        &mut local_plan,
                        &mut local_timings,
                    )?;
                }
                Ok::<_, String>((accepted_samples, local_timings, local_plan))
            }));
        }

        let mut results = Vec::with_capacity(handles.len());
        for handle in handles {
            results.push(handle.join().map_err(|_| {
                "standard MFS DATA-free density preparation worker panicked".to_string()
            })??);
        }
        Ok::<_, String>(results)
    })?;

    let mut accepted_samples = 0usize;
    for (worker_samples, worker_timings, local_plan) in worker_results {
        accepted_samples = accepted_samples.saturating_add(worker_samples);
        *accumulate_timings += worker_timings;
        weighting_plan
            .merge_density_accumulator(local_plan)
            .map_err(|error| error.to_string())?;
    }
    if standard_mfs_profile_detail_enabled() {
        eprintln!(
            "standard_mfs_density_prepare_without_data_parallel threads={} rows={} accepted_samples={} chunk_len={} wall_ms={:.3}",
            thread_count,
            row_count,
            accepted_samples,
            chunk_len,
            duration_ms(started.elapsed()),
        );
    }
    Ok(accepted_samples)
}

#[allow(clippy::too_many_arguments)]
fn standard_mfs_frequency_scales_for_selected_rows(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
    phase_center: &PhaseCenter,
    selected_rows: &[SelectedMainRow],
    derived_engine: Option<&MsCalEngine>,
) -> Result<Vec<f64>, String> {
    let mut prepared = PreparedSelection::new_standard_mfs_from_table_values(
        config,
        table_values,
        phase_center.clone(),
        false,
    )?;
    let mut row_frequency_scales = Vec::with_capacity(selected_rows.len());
    for selected_row in selected_rows {
        row_frequency_scales
            .push(prepared.mfs_imaging_frequency_scale_for_row(selected_row, derived_engine)?);
    }
    Ok(row_frequency_scales)
}

#[allow(clippy::too_many_arguments)]
fn accumulate_standard_mfs_density_essentials_rows(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
    phase_center: &PhaseCenter,
    selected_rows: &[SelectedMainRow],
    rows: &[MsImagingEssentials],
    row_frequency_scales: &[f64],
    weighting_plan: &mut StandardMfsStreamingWeightingPlan,
    accumulate_timings: &mut AccumulateRowTimings,
) -> Result<usize, String> {
    if selected_rows.len() != rows.len() {
        return Err(format!(
            "internal error: selected row count {} differs from essentials row count {}",
            selected_rows.len(),
            rows.len()
        ));
    }
    if row_frequency_scales.len() != rows.len() {
        return Err(format!(
            "internal error: frequency-scale count {} differs from essentials row count {}",
            row_frequency_scales.len(),
            rows.len()
        ));
    }
    let thread_count = standard_mfs_density_prepare_threads(rows.len());
    if thread_count <= 1 {
        let mut prepared = PreparedSelection::new_standard_mfs_from_table_values(
            config,
            table_values,
            phase_center.clone(),
            false,
        )?;
        let mut accepted_samples = 0usize;
        for ((selected_row, row), &mfs_frequency_scale) in selected_rows
            .iter()
            .zip(rows.iter())
            .zip(row_frequency_scales.iter())
        {
            if row.spw_id != selected_row.spw_id {
                return Err(format!(
                    "row {} SPW mismatch: selected row has {}, essentials block has {}",
                    selected_row.row_index, selected_row.spw_id, row.spw_id
                ));
            }
            accepted_samples += prepared
                .accumulate_standard_mfs_density_essentials_row_with_frequency_scale(
                    row,
                    mfs_frequency_scale,
                    weighting_plan,
                    accumulate_timings,
                )?;
        }
        return Ok(accepted_samples);
    }

    let started = Instant::now();
    let chunk_len = rows.len().div_ceil(thread_count).max(1);
    let plan_template = &*weighting_plan;
    let worker_results =
        thread::scope(|scope| {
            let mut handles = Vec::with_capacity(thread_count);
            for ((selected_chunk, row_chunk), scale_chunk) in selected_rows
                .chunks(chunk_len)
                .zip(rows.chunks(chunk_len))
                .zip(row_frequency_scales.chunks(chunk_len))
            {
                let table_values = table_values.clone();
                let phase_center = phase_center.clone();
                handles.push(scope.spawn(move || {
                    let mut prepared = PreparedSelection::new_standard_mfs_from_table_values(
                        config,
                        &table_values,
                        phase_center,
                        false,
                    )?;
                    let mut local_plan = plan_template
                        .fork_density_accumulator()
                        .map_err(|error| error.to_string())?;
                    let mut local_timings = AccumulateRowTimings::default();
                    let mut accepted_samples = 0usize;
                    for ((selected_row, row), &mfs_frequency_scale) in selected_chunk
                        .iter()
                        .zip(row_chunk.iter())
                        .zip(scale_chunk.iter())
                    {
                        if row.spw_id != selected_row.spw_id {
                            return Err(format!(
                                "row {} SPW mismatch: selected row has {}, essentials block has {}",
                                selected_row.row_index, selected_row.spw_id, row.spw_id
                            ));
                        }
                        accepted_samples += prepared
                            .accumulate_standard_mfs_density_essentials_row_with_frequency_scale(
                                row,
                                mfs_frequency_scale,
                                &mut local_plan,
                                &mut local_timings,
                            )?;
                    }
                    Ok::<_, String>((accepted_samples, local_timings, local_plan))
                }));
            }

            let mut results = Vec::with_capacity(handles.len());
            for handle in handles {
                results.push(handle.join().map_err(|_| {
                    "standard MFS density preparation worker panicked".to_string()
                })??);
            }
            Ok::<_, String>(results)
        })?;

    let mut accepted_samples = 0usize;
    for (worker_samples, worker_timings, local_plan) in worker_results {
        accepted_samples = accepted_samples.saturating_add(worker_samples);
        *accumulate_timings += worker_timings;
        weighting_plan
            .merge_density_accumulator(local_plan)
            .map_err(|error| error.to_string())?;
    }
    if standard_mfs_profile_detail_enabled() {
        eprintln!(
            "standard_mfs_density_prepare_parallel threads={} rows={} accepted_samples={} chunk_len={} wall_ms={:.3}",
            thread_count,
            rows.len(),
            accepted_samples,
            chunk_len,
            duration_ms(started.elapsed()),
        );
    }
    Ok(accepted_samples)
}

#[allow(clippy::too_many_arguments)]
fn stream_standard_mfs_density_and_routed_visibility_cache_row_blocks<F>(
    ms: &MeasurementSet,
    config: &CliConfig,
    data_column_kind: VisibilityDataColumn,
    selection: &SelectedRowsContext,
    table_values: &PreparedSelectionTableValues,
    active_selected_rows: &[SelectedMainRow],
    derived_engine: Option<&MsCalEngine>,
    channel_axes: Arc<MsImagingChannelAxisCatalog>,
    channel_read_range: Option<SelectedChannelReadRange>,
    geometry_columns: &PreparedGeometryColumnCache,
    row_block_rows: usize,
    prepare_started_at: Instant,
    prepare_stage_timings: &mut PreparePlaneInputStageTimings,
    accumulate_timings: &mut AccumulateRowTimings,
    pass_stats: &mut StandardMfsStreamingPassStats,
    weighting_plan: &mut StandardMfsStreamingWeightingPlan,
    planned_sample_builder: &StandardMfsPlannedSampleBuilder,
    mut consume: F,
) -> Result<usize, String>
where
    F: FnMut(&StandardMfsRoutedVisibilityBlock) -> Result<(), ImagingError>,
{
    let mut accepted_density_samples = 0usize;
    let mut prepared = PreparedSelection::new_standard_mfs_from_table_values(
        config,
        table_values,
        selection.phase_center.clone(),
        false,
    )?;
    let source_channel_indices =
        Arc::<[usize]>::from(prepared.source_channel_indices.clone().into_boxed_slice());
    let mut next_input_seq = 0u64;
    for row_chunk in active_selected_rows.chunks(row_block_rows) {
        let stage_started_at = Instant::now();
        let (block, read_timings) = read_ms_imaging_essentials_block(
            ms,
            data_column_kind,
            Arc::clone(&channel_axes),
            geometry_columns,
            row_chunk,
            channel_read_range,
        )?;
        let get_ms_values_elapsed = stage_started_at.elapsed();
        prepare_stage_timings.get_ms_values_into_processing_buffer += get_ms_values_elapsed;
        pass_stats.add_get_ms_values_detail(GetMsValuesTimings {
            data_column: read_timings.data_column,
            flag_column: read_timings.flag_column,
            weight_column: read_timings.weight_column,
            weight_spectrum: read_timings.weight_spectrum,
            geometry_rows: read_timings.uvw_column,
        });

        let stage_started_at = Instant::now();
        let mut block_density_samples = 0usize;
        let mut block_candidate_samples = 0usize;
        let mut block_planned_samples = 0usize;
        let mut block_detail = StandardMfsPlannedRowSampleDetailTimings::default();
        let mut routed_block = StandardMfsRoutedVisibilityBlock::default();
        let rows = block.rows;
        let row_frequency_scales = standard_mfs_frequency_scales_for_selected_rows(
            config,
            table_values,
            &selection.phase_center,
            row_chunk,
            derived_engine,
        )?;
        let before_accumulate = *accumulate_timings;
        block_density_samples += accumulate_standard_mfs_density_essentials_rows(
            config,
            table_values,
            &selection.phase_center,
            row_chunk,
            &rows,
            &row_frequency_scales,
            weighting_plan,
            accumulate_timings,
        )?;
        for ((selected_row, row), &mfs_frequency_scale) in
            row_chunk.iter().zip(rows).zip(row_frequency_scales.iter())
        {
            if row.spw_id != selected_row.spw_id {
                return Err(format!(
                    "row {} SPW mismatch: selected row has {}, essentials block has {}",
                    selected_row.row_index, selected_row.spw_id, row.spw_id
                ));
            }
            let counts = prepared.stream_standard_mfs_routed_essentials_row_visibility_runs(
                selected_row,
                row,
                derived_engine,
                Some(mfs_frequency_scale),
                Arc::clone(&source_channel_indices),
                planned_sample_builder,
                &mut next_input_seq,
                &mut routed_block,
            )?;
            block_candidate_samples += counts.candidate_samples;
            block_planned_samples += counts.planned_samples;
            block_detail.add(counts.detail);
        }
        let consumer_started_at = Instant::now();
        consume(&routed_block).map_err(|error| error.to_string())?;
        pass_stats.add_consumer(consumer_started_at.elapsed());
        let prepare_processing_elapsed = stage_started_at.elapsed();
        prepare_stage_timings.prepare_processing_buffer += prepare_processing_elapsed;
        pass_stats.add_accumulate_rows_detail(accumulate_timings.delta_since(before_accumulate));
        pass_stats.add_planned_sample_counts(
            block_candidate_samples,
            block_planned_samples,
            block_planned_samples.saturating_mul(49),
        );
        pass_stats.add_planned_sample_detail(block_detail);
        pass_stats.record_density_block(
            block_density_samples,
            get_ms_values_elapsed,
            prepare_processing_elapsed,
        );
        accepted_density_samples = accepted_density_samples.saturating_add(block_density_samples);
        if frontend_progress_enabled() {
            eprintln!(
                "frontend stage=prepare_plane_input/density_routed_cache_block rows_done={} rows_total={} accepted_density_samples={} total_elapsed_s={:.3}",
                accumulate_timings.rows_seen,
                active_selected_rows.len(),
                accepted_density_samples,
                prepare_started_at.elapsed().as_secs_f64(),
            );
        }
    }
    Ok(accepted_density_samples)
}

