#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct FixedTileResidencyEstimate {
    bytes: usize,
    tile_limit: usize,
    tile_edge: usize,
    center_boundary_anchor: bool,
    anchor_label: &'static str,
}

fn standard_mfs_execution_config(config: &CliConfig) -> StandardMfsExecutionConfig {
    let fixed_tile_resident = estimated_fixed_tile_residency(config);
    let mut execution = StandardMfsExecutionConfig::default();
    execution.minor_cycle_backend = standard_mfs_minor_cycle_backend_for_config(config);
    execution.fixed_tile_resident_bytes =
        Some(fixed_tile_resident.bytes).filter(|bytes| *bytes > 0);
    execution.fixed_tile_edge = Some(fixed_tile_resident.tile_edge).filter(|edge| *edge > 0);
    execution.fixed_tile_center_boundary = fixed_tile_resident.center_boundary_anchor;
    execution.fixed_tile_max_live_row_blocks = env_usize("CASA_RS_STANDARD_MFS_QUEUE_BLOCKS")
        .filter(|value| *value > 0)
        .map(|value| value.min(2))
        .unwrap_or(1);
    execution
}

fn standard_mfs_execution_config_with_plan(
    config: &CliConfig,
    strategy: &StandardMfsMemoryPlan,
) -> StandardMfsExecutionConfig {
    let mut execution = standard_mfs_execution_config(config);
    execution.metal_grouped_input_cache = strategy.metal_grouped_input_cache_enabled;
    execution
}

fn estimated_fixed_tile_residency(config: &CliConfig) -> FixedTileResidencyEstimate {
    estimated_fixed_tile_residency_with_backend(
        config,
        standard_mfs_fixed_tile_backend_enabled_for_frontend(),
    )
}

fn estimated_fixed_tile_residency_with_backend(
    config: &CliConfig,
    fixed_tile_backend_enabled: bool,
) -> FixedTileResidencyEstimate {
    if !fixed_tile_backend_enabled {
        return FixedTileResidencyEstimate::default();
    }
    let center_boundary_anchor = standard_mfs_center_boundary_anchor_for_frontend();
    let anchor_label = standard_mfs_tile_anchor_label_for_frontend();
    let memory_target = standard_mfs_memory_target(config);
    let default_tile_budget_bytes = memory_target
        .target_bytes
        .checked_div(4)
        .unwrap_or(0)
        .max(256 * 1024 * 1024);
    let tile_budget_bytes = env_usize("CASA_RS_STANDARD_MFS_TILE_RESIDENT_MB")
        .filter(|value| *value > 0)
        .map(|value| value.saturating_mul(1024 * 1024))
        .unwrap_or(default_tile_budget_bytes);
    if anchor_label == "center_quadrants" && env_usize("CASA_RS_STANDARD_MFS_TILE_EDGE").is_none() {
        return estimate_fixed_tile_quadrant_residency(config).with_budget(tile_budget_bytes);
    }
    let tile_edge = env_usize("CASA_RS_STANDARD_MFS_TILE_EDGE")
        .filter(|value| *value > 0)
        .unwrap_or_else(|| {
            let edge32 = estimate_fixed_tile_residency_for_edge(config, 32, center_boundary_anchor);
            if edge32.bytes <= tile_budget_bytes {
                32
            } else {
                64
            }
        });
    estimate_fixed_tile_residency_for_edge(config, tile_edge, center_boundary_anchor)
        .with_anchor_label(anchor_label)
        .with_budget(tile_budget_bytes)
}

fn estimate_fixed_tile_residency_for_edge(
    config: &CliConfig,
    tile_edge: usize,
    center_boundary_anchor: bool,
) -> FixedTileResidencyEstimate {
    let halo = 3usize;
    let grid_side = casa_composite_padded_len_estimate(config.imsize, 1.2);
    let tiles_per_axis =
        estimated_fixed_tile_axis_count(grid_side, tile_edge, center_boundary_anchor);
    let tile_count = tiles_per_axis.saturating_mul(tiles_per_axis).max(1);
    let padded_tile_side = tile_edge.saturating_add(2 * halo).min(grid_side);
    let two_grid_tile_bytes = padded_tile_side
        .saturating_mul(padded_tile_side)
        .saturating_mul(2)
        .saturating_mul(std::mem::size_of::<Complex64>());
    FixedTileResidencyEstimate {
        bytes: tile_count.saturating_mul(two_grid_tile_bytes),
        tile_limit: tile_count,
        tile_edge,
        center_boundary_anchor,
        anchor_label: if center_boundary_anchor {
            "center_boundary"
        } else {
            "zero"
        },
    }
}

fn estimate_fixed_tile_quadrant_residency(config: &CliConfig) -> FixedTileResidencyEstimate {
    let halo = 3usize;
    let grid_side = casa_composite_padded_len_estimate(config.imsize, 1.2);
    let center = grid_side / 2;
    let tile_edge = center.max(grid_side.saturating_sub(center)).max(1);
    let bounds = [(0usize, center), (center, grid_side)];
    let mut halo_cells = 0usize;
    let mut tile_limit = 0usize;
    for (x0, x1) in bounds {
        if x0 >= x1 {
            continue;
        }
        for (y0, y1) in bounds {
            if y0 >= y1 {
                continue;
            }
            tile_limit += 1;
            let halo_width = x1
                .saturating_add(halo)
                .min(grid_side)
                .saturating_sub(x0.saturating_sub(halo));
            let halo_height = y1
                .saturating_add(halo)
                .min(grid_side)
                .saturating_sub(y0.saturating_sub(halo));
            halo_cells = halo_cells.saturating_add(halo_width.saturating_mul(halo_height));
        }
    }
    FixedTileResidencyEstimate {
        bytes: halo_cells
            .saturating_mul(2)
            .saturating_mul(std::mem::size_of::<Complex64>()),
        tile_limit: tile_limit.max(1),
        tile_edge,
        center_boundary_anchor: true,
        anchor_label: "center_quadrants",
    }
}

impl FixedTileResidencyEstimate {
    fn with_anchor_label(self, anchor_label: &'static str) -> Self {
        Self {
            anchor_label,
            ..self
        }
    }

    fn with_budget(self, budget_bytes: usize) -> Self {
        if self.tile_limit == 0 || self.bytes <= budget_bytes {
            return self;
        }
        let per_tile_bytes = self.bytes.div_ceil(self.tile_limit);
        let tile_limit = (budget_bytes / per_tile_bytes).clamp(1, self.tile_limit);
        Self {
            bytes: tile_limit.saturating_mul(per_tile_bytes),
            tile_limit,
            tile_edge: self.tile_edge,
            center_boundary_anchor: self.center_boundary_anchor,
            anchor_label: self.anchor_label,
        }
    }
}

fn estimated_fixed_tile_axis_count(
    grid_len: usize,
    tile_edge: usize,
    center_boundary_anchor: bool,
) -> usize {
    if grid_len == 0 || tile_edge == 0 {
        return 0;
    }
    let origin = if center_boundary_anchor {
        (grid_len / 2) % tile_edge
    } else {
        0
    };
    if origin == 0 {
        grid_len.div_ceil(tile_edge)
    } else if grid_len <= origin {
        1
    } else {
        1 + (grid_len - origin).div_ceil(tile_edge)
    }
}

fn standard_mfs_center_boundary_anchor_for_frontend() -> bool {
    env::var("CASA_RS_STANDARD_MFS_TILE_ANCHOR")
        .map(|value| match value.trim().to_ascii_lowercase().as_str() {
            "zero" => false,
            "center_boundary" | "center-boundary" | "center" | "boundary" | "center_quadrants"
            | "center-quadrants" | "center_quadrant" | "center-quadrant" | "quadrants"
            | "quadrant" | "four" | "4" => true,
            _ => true,
        })
        .unwrap_or(true)
}

fn standard_mfs_tile_anchor_label_for_frontend() -> &'static str {
    env::var("CASA_RS_STANDARD_MFS_TILE_ANCHOR")
        .map(|value| match value.trim().to_ascii_lowercase().as_str() {
            "zero" => "zero",
            "center_quadrants" | "center-quadrants" | "center_quadrant" | "center-quadrant"
            | "quadrants" | "quadrant" | "four" | "4" => "center_quadrants",
            _ => "center_boundary",
        })
        .unwrap_or("center_boundary")
}

fn standard_mfs_fixed_tile_backend_enabled_for_frontend() -> bool {
    env::var("CASA_RS_STANDARD_MFS_BACKEND")
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "fixed_tile" | "fixed-tile" | "tile" | "tiled" | "streaming_fixed_tile" | "metal"
            )
        })
        .unwrap_or(false)
}

fn standard_mfs_fixed_tile_clean_uses_sample_streaming(
    config: &CliConfig,
    gridder_mode: &GridderMode,
) -> bool {
    matches!(gridder_mode, GridderMode::Standard)
        && matches!(config.w_term_mode, WTermMode::None)
        && (env_standard_mfs_grid_threads() == Some(1)
            || standard_mfs_fixed_tile_backend_enabled_for_frontend())
}

fn standard_mfs_metal_grouped_residual_backend_selected_for_frontend() -> bool {
    env::var("CASA_RS_STANDARD_MFS_RESIDUAL_BACKEND")
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "metal-row-run-grouped"
                    | "metal_row_run_grouped"
                    | "metal-grouped"
                    | "metal_grouped"
            )
        })
        .unwrap_or(false)
}

fn standard_mfs_metal_grouped_initial_dirty_backend_selected_for_frontend() -> bool {
    env::var("CASA_RS_STANDARD_MFS_INITIAL_DIRTY_BACKEND")
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "metal-row-run-grouped"
                    | "metal_row_run_grouped"
                    | "metal-grouped"
                    | "metal_grouped"
            )
        })
        .unwrap_or(false)
}

fn standard_mfs_product_status_for_frontend() -> &'static str {
    env::var("CASA_RS_STANDARD_MFS_BACKEND")
        .map(|value| match value.trim().to_ascii_lowercase().as_str() {
            "fixed_tile" | "fixed-tile" | "tile" | "tiled" | "streaming_fixed_tile" => "fixed_tile",
            "metal" => "metal_dirty_psf_preview",
            _ => "cpu",
        })
        .unwrap_or("cpu")
}

fn casa_composite_padded_len_estimate(image_len: usize, padding_factor: f64) -> usize {
    let mut padded = diagnostic_padded_len(image_len, padding_factor);
    while !is_casa_composite_len_estimate(padded) {
        padded += 2;
    }
    padded
}

fn diagnostic_padded_len(image_len: usize, padding_factor: f64) -> usize {
    let padded = (padding_factor * image_len as f64 - 0.5).floor() as usize;
    let padded = padded.max(image_len);
    if padded % 2 == 0 { padded } else { padded + 1 }
}

fn is_casa_composite_len_estimate(mut value: usize) -> bool {
    for factor in [2, 3, 5] {
        while value > 1 && value % factor == 0 {
            value /= factor;
        }
    }
    value == 1
}

fn estimated_worker_staging_bytes(config: &CliConfig) -> usize {
    let worker_grids = env_standard_mfs_grid_threads()
        .filter(|value| *value > 1)
        .unwrap_or(1);
    if worker_grids <= 1 {
        return 0;
    }
    let density_worker_staging = config
        .imsize
        .saturating_mul(config.imsize)
        .saturating_mul(worker_grids)
        .saturating_mul(std::mem::size_of::<f32>());
    let conservative_padded_side = config.imsize.saturating_mul(13).div_ceil(10);
    let residual_worker_staging = conservative_padded_side
        .saturating_mul(conservative_padded_side)
        .saturating_mul(worker_grids)
        .saturating_mul(std::mem::size_of::<Complex64>())
        .saturating_mul(2);
    density_worker_staging.saturating_add(residual_worker_staging)
}

fn estimated_gpu_staging_bytes() -> usize {
    env_usize("CASA_RS_IMAGING_GPU_STAGING_MB")
        .filter(|value| *value > 0)
        .map(|value| value.saturating_mul(1024 * 1024))
        .unwrap_or(0)
}

fn estimated_standard_mfs_routed_replay_cache_bytes(
    active_row_count: usize,
    selected_channel_count: usize,
) -> usize {
    active_row_count
        .saturating_mul(selected_channel_count.max(1))
        .saturating_mul(ESTIMATED_STANDARD_MFS_ROUTED_REPLAY_CACHE_BYTES_PER_LANE)
}

fn estimated_standard_mfs_metal_grouped_input_cache_bytes(
    active_row_count: usize,
    selected_channel_count: usize,
) -> usize {
    let logical_lanes = active_row_count.saturating_mul(selected_channel_count.max(1));
    logical_lanes.saturating_mul(ESTIMATED_STANDARD_MFS_METAL_GROUPED_INPUT_CACHE_BYTES_PER_LANE)
}

fn load_prepared_selection_table_values(
    ddid: usize,
    ddid_info: &[Option<(usize, usize)>],
    spectral_window: &casa_ms::subtables::spectral_window::MsSpectralWindow<'_>,
    polarization: &casa_ms::subtables::polarization::MsPolarization<'_>,
) -> Result<PreparedSelectionTableValues, String> {
    let (spw_id, polarization_id) = ddid_info
        .get(ddid)
        .copied()
        .flatten()
        .ok_or_else(|| format!("map DDID {ddid} to SPW/POLARIZATION"))?;
    let spw_freqs_hz = spectral_window
        .chan_freq(spw_id)
        .map_err(|error| format!("read CHAN_FREQ: {error}"))?;
    let spw_widths_hz = spectral_window
        .chan_width(spw_id)
        .map_err(|error| format!("read CHAN_WIDTH: {error}"))?;
    let freq_ref = FrequencyRef::from_casacore_code(
        spectral_window
            .meas_freq_ref(spw_id)
            .map_err(|error| format!("read MEAS_FREQ_REF: {error}"))?,
    )
    .unwrap_or(FrequencyRef::TOPO);
    let corr_types = polarization
        .corr_type(polarization_id)
        .map_err(|error| format!("read CORR_TYPE: {error}"))?;
    Ok(PreparedSelectionTableValues {
        spw_id,
        spw_freqs_hz,
        spw_widths_hz,
        freq_ref,
        corr_types,
    })
}

fn selected_channel_count_estimate_from_table_values(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
) -> usize {
    if let Some(channel_count) = config.channel_count {
        return channel_count.max(1);
    }
    table_values.spw_freqs_hz.len().max(1)
}

fn standard_mfs_density_source_plan(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
) -> StandardMfsDensitySourcePlan {
    plan_standard_mfs_density_source(StandardMfsDensitySourcePlanRequest {
        cube_like: config.spectral_mode.is_cube_like(),
        dirty_only: clean_is_dirty(config),
        target_channel_count: config.channel_count,
        full_source_channel_count: table_values.spw_freqs_hz.len(),
        per_channel_weight_density: effective_per_channel_weight_density(config),
        weighting: config.weighting,
    })
}

fn standard_mfs_density_source_config(
    config: &CliConfig,
    plan: StandardMfsDensitySourcePlan,
) -> CliConfig {
    let mut density_config = config.clone();
    if plan.uses_distinct_density_source {
        // CASA cube weighting with perchanweightdensity=false derives one
        // shared density grid from the selected SPW channel domain, even when
        // the target cube has a single output channel.
        density_config.spectral_mode = SpectralMode::Mfs;
        density_config.channel_start = plan.density_channel_start;
        density_config.channel_count = plan.density_channel_count;
    }
    density_config
}

type SelectedChannelReadRange = VisibilityChannelReadRange;

#[derive(Clone, Copy)]
enum CubeOneChannelBriggsPolarization {
    Explicit {
        corr_index: usize,
    },
    CollapsedPair {
        first_corr_index: usize,
        second_corr_index: usize,
    },
}

struct CubeOneChannelBriggsStreamingPlan {
    cube_setup: CubeSpectralSetup,
    source_channel_indices: Arc<[usize]>,
    source_channel_frequencies_hz: Arc<[f64]>,
    source_channel_widths_hz: Arc<[f64]>,
    row_spectral_cache: HashMap<(u64, usize), Arc<CubeRowSpectralContributions>>,
    density_grids: Vec<Array2<f32>>,
    f2_by_plane: Vec<f32>,
    weighting: WeightingMode,
    fractional_bandwidth: f64,
    polarization: CubeOneChannelBriggsPolarization,
}

impl CubeOneChannelBriggsStreamingPlan {
    fn finish_density(&mut self) {
        self.f2_by_plane = self
            .density_grids
            .iter()
            .enumerate()
            .map(|(plane, density)| {
                let f2 = casa_cube_briggs_f2(self.weighting, density);
                if std::env::var_os("CASA_RS_TRACE_RUST_WEIGHTING").is_some() {
                    let density_sum = density.iter().map(|value| f64::from(*value)).sum::<f64>();
                    let density_max = density.iter().copied().fold(0.0f32, f32::max);
                    let density_nonzero = density.iter().filter(|value| **value > 0.0).count();
                    eprintln!(
                        "CASA_RS_TRACE_RUST_WEIGHTING cube_one_channel_briggs_streaming plane={plane} density_sum={density_sum:.12e} density_max={density_max:.12e} density_nonzero={density_nonzero} f2={f2:.12e}"
                    );
                }
                f2
            })
            .collect();
    }

    fn row_spectral_contributions(
        &mut self,
        selected_row: &SelectedMainRow,
        derived_engine: Option<&MsCalEngine>,
    ) -> Result<Arc<CubeRowSpectralContributions>, String> {
        let row_time_mjd_sec = selected_row.time_mjd_seconds.ok_or_else(|| {
            "internal error: missing row time for cube Briggs weighting".to_string()
        })?;
        let cache_key = (row_time_mjd_sec.to_bits(), selected_row.field_id);
        if let Some(cached) = self.row_spectral_cache.get(&cache_key) {
            return Ok(Arc::clone(cached));
        }
        let derived_engine = derived_engine.ok_or_else(|| {
            "internal error: missing derived engine for cube Briggs weighting".to_string()
        })?;
        let computed = Arc::new(
            self.cube_setup
                .row_spectral_contributions(
                    &self.source_channel_frequencies_hz,
                    &self.source_channel_widths_hz,
                    row_time_mjd_sec,
                    selected_row.field_id,
                    derived_engine,
                )
                .map_err(|error| error.to_string())?,
        );
        self.row_spectral_cache
            .insert(cache_key, Arc::clone(&computed));
        Ok(computed)
    }

    fn row_spectral_contributions_readonly(
        &self,
        selected_row: &SelectedMainRow,
        derived_engine: Option<&MsCalEngine>,
    ) -> Result<Arc<CubeRowSpectralContributions>, String> {
        let row_time_mjd_sec = selected_row.time_mjd_seconds.ok_or_else(|| {
            "internal error: missing row time for cube Briggs weighting".to_string()
        })?;
        let cache_key = (row_time_mjd_sec.to_bits(), selected_row.field_id);
        if let Some(cached) = self.row_spectral_cache.get(&cache_key) {
            return Ok(Arc::clone(cached));
        }
        let derived_engine = derived_engine.ok_or_else(|| {
            "internal error: missing derived engine for cube Briggs weighting".to_string()
        })?;
        Ok(Arc::new(
            self.cube_setup
                .row_spectral_contributions(
                    &self.source_channel_frequencies_hz,
                    &self.source_channel_widths_hz,
                    row_time_mjd_sec,
                    selected_row.field_id,
                    derived_engine,
                )
                .map_err(|error| error.to_string())?,
        ))
    }
}

struct CubeOneChannelBriggsStreamingPlanWithGeometry {
    plan: CubeOneChannelBriggsStreamingPlan,
    geometry: ImageGeometry,
}

impl CubeOneChannelBriggsStreamingPlanWithGeometry {
    fn finish_density(&mut self) {
        self.plan.finish_density();
    }

    fn accumulate_density_row(
        &mut self,
        selected_row: &SelectedMainRow,
        row: &MsImagingDensityEssentials,
        derived_engine: Option<&MsCalEngine>,
    ) -> Result<usize, String> {
        if !row.gridable {
            return Ok(0);
        }
        let contributions = self
            .plan
            .row_spectral_contributions(selected_row, derived_engine)?;
        let mut accepted = 0usize;
        for grid in &contributions.padded_grid_channel_contributions {
            let Some(weight) = cube_one_channel_briggs_density_weight(
                row,
                self.plan.polarization,
                &self.plan.source_channel_indices,
                &grid.contributions,
            )?
            else {
                continue;
            };
            let Some(density) = self.plan.density_grids.get_mut(grid.output_channel) else {
                continue;
            };
            let lambda_scale = grid.grid_frequency_hz / SPEED_OF_LIGHT_M_PER_S;
            let Some((x, y)) = casa_cube_briggs_gridft_density_cell_from_lambda(
                density.dim(),
                row.u_m * lambda_scale,
                row.v_m * lambda_scale,
                self.geometry.cell_size_rad,
            ) else {
                continue;
            };
            density[(x, y)] += weight;
            let (nx, ny) = density.dim();
            let mirror_x = nx.saturating_sub(x);
            let mirror_y = ny.saturating_sub(y);
            if mirror_x < nx && mirror_y < ny {
                density[(mirror_x, mirror_y)] += weight;
            }
            accepted += 1;
        }
        Ok(accepted)
    }

    fn preweighted_row_for_target_readonly(
        &self,
        selected_row: &SelectedMainRow,
        row: &StandardMfsVisibilityRow,
        derived_engine: Option<&MsCalEngine>,
    ) -> Result<StandardMfsVisibilityRow, String> {
        if row.source_channel_indices.len() != row.channel_lambda_scales.len() {
            return Err(format!(
                "one-channel cube Briggs preweighting source slot count {} differs from lambda scale count {}",
                row.source_channel_indices.len(),
                row.channel_lambda_scales.len()
            ));
        }
        let contributions = self
            .plan
            .row_spectral_contributions_readonly(selected_row, derived_engine)?;

        let corr_count = row
            .data
            .shape()
            .first()
            .copied()
            .unwrap_or(row.weight.len())
            .max(row.weight.len());
        let local_channel_count = row.data.shape().get(1).copied().unwrap_or(0);
        let mut preweighted_spectrum = Array2::<f32>::zeros((corr_count, local_channel_count));
        for (source_slot, &source_channel) in row.source_channel_indices.iter().enumerate() {
            let final_weight =
                self.preweighted_source_slot_weight(row, &contributions, source_slot)?;
            let local_channel =
                local_channel_index(source_channel, row.channel_origin, local_channel_count)?;
            match row.polarization {
                StandardMfsVisibilityPolarization::Explicit { corr_index, .. } => {
                    *preweighted_spectrum
                        .get_mut((corr_index, local_channel))
                        .ok_or_else(|| {
                            format!(
                                "routed preweighted WEIGHT_SPECTRUM index [{corr_index}, {local_channel}] out of bounds"
                            )
                        })? = final_weight;
                }
                StandardMfsVisibilityPolarization::CollapsedPair {
                    first_corr_index,
                    second_corr_index,
                    ..
                } => {
                    *preweighted_spectrum
                        .get_mut((first_corr_index, local_channel))
                        .ok_or_else(|| {
                            format!(
                                "routed preweighted WEIGHT_SPECTRUM index [{first_corr_index}, {local_channel}] out of bounds"
                            )
                        })? = final_weight;
                    *preweighted_spectrum
                        .get_mut((second_corr_index, local_channel))
                        .ok_or_else(|| {
                            format!(
                                "routed preweighted WEIGHT_SPECTRUM index [{second_corr_index}, {local_channel}] out of bounds"
                            )
                        })? = final_weight;
                }
            }
        }
        Ok(preweighted_routed_row_with_weight_spectrum(
            row,
            preweighted_spectrum,
        ))
    }

    fn preweighted_source_slot_weight(
        &self,
        row: &StandardMfsVisibilityRow,
        contributions: &CubeRowSpectralContributions,
        source_slot: usize,
    ) -> Result<f32, String> {
        let Some(density_plane) = contributions
            .padded_source_channel_output_map
            .get(source_slot)
            .copied()
            .flatten()
        else {
            return Ok(0.0);
        };
        let lambda_scale = *row.channel_lambda_scales.get(source_slot).ok_or_else(|| {
            format!("routed row lambda scale slot {source_slot} is out of bounds")
        })?;
        let u_lambda = row.uvw_m[0] * lambda_scale;
        let v_lambda = row.uvw_m[1] * lambda_scale;
        let Some(density_grid) = self.plan.density_grids.get(density_plane) else {
            return Err(format!(
                "one-channel cube Briggs density plane {density_plane} is out of bounds"
            ));
        };
        let Some((x, y)) = casa_cube_briggs_density_cell_from_lambda(
            density_grid.dim(),
            u_lambda,
            v_lambda,
            self.geometry.cell_size_rad,
        ) else {
            return Ok(0.0);
        };
        let density = density_grid[(x, y)];
        let f2 = self
            .plan
            .f2_by_plane
            .get(density_plane)
            .copied()
            .unwrap_or(0.0);
        let natural_weight = routed_row_natural_weight_for_source_slot(row, source_slot)?;
        if !(natural_weight.is_finite()
            && natural_weight > 0.0
            && density.is_finite()
            && density > 0.0
            && f2.is_finite()
            && f2 > 0.0)
        {
            return Ok(0.0);
        }
        let denominator = casa_cube_briggs_weight_denominator(
            self.plan.weighting,
            self.geometry,
            self.plan.fractional_bandwidth,
            u_lambda,
            v_lambda,
            density,
            f2,
        );
        if denominator.is_finite() && denominator > 0.0 {
            Ok(natural_weight / denominator)
        } else {
            Ok(0.0)
        }
    }
}

fn cube_one_channel_briggs_streaming_plan(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
    selection: &SelectedRowsContext,
    geometry: ImageGeometry,
    derived_engine: Option<&MsCalEngine>,
) -> Result<
    Option<(
        CubeOneChannelBriggsStreamingPlanWithGeometry,
        SelectedChannelReadRange,
    )>,
    String,
> {
    let target_density_cube_clean = !clean_is_dirty(config)
        && config.spectral_mode.is_cube_like()
        && config.channel_count == Some(1);
    if !(config.spectral_mode.is_cube_like()
        && config.channel_count == Some(1)
        && (effective_per_channel_weight_density(config) || target_density_cube_clean)
        && matches!(
            config.weighting,
            WeightingMode::Uniform
                | WeightingMode::Briggs { .. }
                | WeightingMode::BriggsBwTaper { .. }
        ))
    {
        return Ok(None);
    }
    let derived_engine = derived_engine.ok_or_else(|| {
        "one-channel cube Briggs streaming requires a spectral-frame engine".to_string()
    })?;
    let mut cube_axis = config.cube_axis.clone();
    // CASA's BriggsCubeWeightor builds its padded channel map on the selected
    // SPW channel grid for channel-mode one-plane cubes. The image spectral
    // coordinate may still be in the requested output frame, but the weightor
    // density lookup follows native channel numbering.
    cube_axis.specmode = CubeSpecMode::Cubedata;
    let explicit_channel_selector = selected_spw_channel_selector(config, table_values.spw_id)?;
    if cube_axis.start.is_none() {
        cube_axis.start = config
            .channel_start
            .map(|value| CubeAxisValue::Channel(value as i32))
            .or_else(|| {
                explicit_channel_selector
                    .as_ref()
                    .and_then(|selector| {
                        resolve_channel_selector_selection(&table_values.spw_freqs_hz, selector)
                            .ok()
                            .and_then(|selection| selection.indices.first().copied())
                    })
                    .map(|value| CubeAxisValue::Channel(value as i32))
            });
    }
    let cube_context = cube_setup_context_for_selection(selection, Some(derived_engine))?;
    let (cube_setup, support_selection) = CubeSpectralSetup::for_casa_cube_axis(
        table_values.freq_ref,
        &table_values.spw_freqs_hz,
        &table_values.spw_widths_hz,
        1,
        &cube_axis,
        cube_context.reference_row_time_mjd_sec,
        cube_context.spectral_frame_field_id,
        cube_context.phase_center_direction.clone(),
        cube_context.time_bounds_mjd_sec,
        cube_context.derived_engine,
    )
    .map_err(|error| error.to_string())?;
    if cube_setup.output_channel_frequencies_hz.len() != 1 {
        return Err(format!(
            "one-channel cube Briggs streaming expected one output channel, resolved {}",
            cube_setup.output_channel_frequencies_hz.len()
        ));
    }
    let density_read_range = SelectedChannelReadRange::from_contiguous_indices(&support_selection.indices)
        .ok_or_else(|| {
            "one-channel cube Briggs support channels are not contiguous; streaming path cannot use bounded reads"
                .to_string()
        })?;
    let source_channel_widths_hz = support_selection
        .indices
        .iter()
        .map(|&index| {
            table_values.spw_widths_hz.get(index).copied().ok_or_else(|| {
                format!(
                    "cube Briggs support channel {index} is outside SPW width array with {} channels",
                    table_values.spw_widths_hz.len()
                )
            })
        })
        .collect::<Result<Vec<_>, String>>()?;
    let explicit_plane = config
        .correlation
        .as_deref()
        .map(parse_plane_stokes)
        .transpose()?;
    let plane_stokes = explicit_plane.unwrap_or(PlaneStokes::I);
    let polarization = if let Some(corr_code) = plane_to_corr_code(plane_stokes) {
        let corr_index = table_values
            .corr_types
            .iter()
            .position(|code| *code == corr_code)
            .ok_or_else(|| {
                format!(
                    "requested raw correlation plane {} is not present",
                    plane_stokes.as_str()
                )
            })?;
        CubeOneChannelBriggsPolarization::Explicit { corr_index }
    } else {
        let (pair, _transform) = plane_stokes
            .derive_pair_selection(&table_values.corr_types)
            .map_err(|error| error.to_string())?;
        CubeOneChannelBriggsPolarization::CollapsedPair {
            first_corr_index: pair.0,
            second_corr_index: pair.1,
        }
    };
    let density_plane_count = cube_setup.output_channel_frequencies_hz.len() + 4;
    let [nx, ny] = geometry.image_shape;
    let selected_frequency_range_hz =
        frequency_range_hz(&cube_setup.output_channel_frequencies_hz)?;
    let plan = CubeOneChannelBriggsStreamingPlan {
        cube_setup,
        source_channel_indices: Arc::from(support_selection.indices.into_boxed_slice()),
        source_channel_frequencies_hz: Arc::from(
            support_selection.frequencies_hz.into_boxed_slice(),
        ),
        source_channel_widths_hz: Arc::from(source_channel_widths_hz.into_boxed_slice()),
        row_spectral_cache: HashMap::new(),
        density_grids: (0..density_plane_count)
            .map(|_| Array2::<f32>::zeros((nx, ny)))
            .collect(),
        f2_by_plane: Vec::new(),
        weighting: config.weighting,
        fractional_bandwidth: fractional_bandwidth_from_range(selected_frequency_range_hz),
        polarization,
    };
    Ok(Some((
        CubeOneChannelBriggsStreamingPlanWithGeometry { plan, geometry },
        density_read_range,
    )))
}

fn cube_axis_for_config(config: &CliConfig) -> CubeAxisConfig {
    let mut cube_axis = config.cube_axis.clone();
    cube_axis.specmode = config.spectral_mode.cube_specmode();
    if cube_axis.start.is_none() {
        cube_axis.start = config
            .channel_start
            .map(|value| CubeAxisValue::Channel(value as i32));
    }
    cube_axis
}

fn direct_nearest_cube_source_read_range(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
    selection: &SelectedRowsContext,
    derived_engine: Option<&MsCalEngine>,
) -> Result<Option<SelectedChannelReadRange>, String> {
    if !(config.spectral_mode.is_cube_like()
        && config.cube_axis.interpolation == CubeInterpolation::Nearest
        && config.weighting == WeightingMode::Natural)
    {
        return Ok(None);
    }
    let cube_context = cube_setup_context_for_selection(selection, derived_engine)?;
    let cube_axis = cube_axis_for_config(config);
    let (cube_setup, _support_selection) = CubeSpectralSetup::for_casa_cube_axis(
        table_values.freq_ref,
        &table_values.spw_freqs_hz,
        &table_values.spw_widths_hz,
        config
            .channel_count
            .unwrap_or(table_values.spw_freqs_hz.len()),
        &cube_axis,
        cube_context.reference_row_time_mjd_sec,
        cube_context.spectral_frame_field_id,
        cube_context.phase_center_direction.clone(),
        cube_context.time_bounds_mjd_sec,
        cube_context.derived_engine,
    )
    .map_err(|error| error.to_string())?;
    let mut source_channels = Vec::new();
    for row_time_mjd_sec in cube_context.time_bounds_mjd_sec {
        let contributions = cube_setup
            .row_spectral_contributions(
                &table_values.spw_freqs_hz,
                &table_values.spw_widths_hz,
                row_time_mjd_sec,
                cube_context.spectral_frame_field_id,
                cube_context.derived_engine,
            )
            .map_err(|error| error.to_string())?;
        source_channels.extend(
            contributions
                .grid_channel_contributions
                .into_iter()
                .flat_map(|grid| grid.contributions)
                .map(|contribution| contribution.source_channel),
        );
    }
    SelectedChannelReadRange::covering_indices(source_channels)
        .ok_or_else(|| {
            "nearest cube source read range produced no direct grid source channels".to_string()
        })
        .map(Some)
}

fn direct_nearest_cube_source_read_ranges_by_output_plane(
    config: &CliConfig,
    nplanes: usize,
    table_values: &PreparedSelectionTableValues,
    selection: &SelectedRowsContext,
    derived_engine: &MsCalEngine,
) -> Result<Option<Vec<Option<SelectedChannelReadRange>>>, String> {
    if !(config.spectral_mode.is_cube_like()
        && config.cube_axis.interpolation == CubeInterpolation::Nearest
        && config.weighting == WeightingMode::Natural)
    {
        return Ok(None);
    }
    let cube_context = cube_setup_context_for_selection(selection, Some(derived_engine))?;
    let cube_axis = cube_axis_for_config(config);
    let (cube_setup, _support_selection) = CubeSpectralSetup::for_casa_cube_axis(
        table_values.freq_ref,
        &table_values.spw_freqs_hz,
        &table_values.spw_widths_hz,
        nplanes,
        &cube_axis,
        cube_context.reference_row_time_mjd_sec,
        cube_context.spectral_frame_field_id,
        cube_context.phase_center_direction.clone(),
        cube_context.time_bounds_mjd_sec,
        cube_context.derived_engine,
    )
    .map_err(|error| error.to_string())?;

    let mut bounds = vec![None::<(usize, usize)>; nplanes];
    for row_time_mjd_sec in cube_context.time_bounds_mjd_sec {
        let contributions = cube_setup
            .row_spectral_contributions(
                &table_values.spw_freqs_hz,
                &table_values.spw_widths_hz,
                row_time_mjd_sec,
                cube_context.spectral_frame_field_id,
                cube_context.derived_engine,
            )
            .map_err(|error| error.to_string())?;
        for grid in contributions.grid_channel_contributions {
            let Some(plane_bounds) = bounds.get_mut(grid.output_channel) else {
                continue;
            };
            for contribution in grid.contributions {
                merge_source_channel_bound(plane_bounds, contribution.source_channel);
            }
        }
    }

    Ok(Some(
        bounds
            .into_iter()
            .map(|bound| {
                bound.map(|(start, end)| SelectedChannelReadRange {
                    start,
                    count: end - start + 1,
                })
            })
            .collect(),
    ))
}

fn merge_source_channel_bound(bound: &mut Option<(usize, usize)>, source_channel: usize) {
    match bound {
        Some((start, end)) => {
            *start = (*start).min(source_channel);
            *end = (*end).max(source_channel);
        }
        None => *bound = Some((source_channel, source_channel)),
    }
}

fn selected_channel_read_range_for_plane_span(
    plane_read_ranges: &[Option<SelectedChannelReadRange>],
    plane_start: usize,
    plane_end: usize,
) -> Option<SelectedChannelReadRange> {
    let mut bound = None::<(usize, usize)>;
    for range in plane_read_ranges
        .get(plane_start..plane_end)
        .into_iter()
        .flatten()
        .flatten()
    {
        merge_source_channel_bound(&mut bound, range.start);
        merge_source_channel_bound(
            &mut bound,
            range.start.saturating_add(range.count).saturating_sub(1),
        );
    }
    bound.map(|(start, end)| SelectedChannelReadRange {
        start,
        count: end - start + 1,
    })
}

fn single_plane_cube_coordinate_metadata(
    config: &CliConfig,
    plane: &PlaneInput,
    table_values: &PreparedSelectionTableValues,
) -> Result<SinglePlaneCubeCoordinateMetadata, String> {
    if !(config.spectral_mode.is_cube_like() && config.channel_count == Some(1)) {
        return Ok(SinglePlaneCubeCoordinateMetadata::default());
    }
    let spectral_delta_hz = plane
        .spectral_frequency_edge_range_hz
        .and_then(spectral_delta_from_range)
        .or_else(|| spectral_delta_from_range(plane.selected_frequency_range_hz));
    if !matches!(config.spectral_mode, SpectralMode::Cubedata) {
        let channel_start = match config.cube_axis.start {
            Some(CubeAxisValue::Channel(channel)) if channel < 0 => {
                return Err(format!(
                    "cube channel start {channel} is negative; channel-mode start must be >= 0"
                ));
            }
            Some(CubeAxisValue::Channel(channel)) => Some(channel as usize),
            _ => config.channel_start,
        };
        let channel_count = match config.cube_axis.width {
            Some(CubeAxisValue::Channel(0)) => {
                return Err("cube channel width must not be zero".to_string());
            }
            Some(CubeAxisValue::Channel(width)) => Some(width.unsigned_abs() as usize),
            _ => config.channel_count,
        };
        let selected = resolve_contiguous_channel_selection(
            &table_values.spw_freqs_hz,
            channel_start,
            channel_count,
        )
        .map_err(|error| error.to_string())?;
        let native_width_hz = selected
            .indices
            .iter()
            .filter_map(|&channel_index| table_values.spw_widths_hz.get(channel_index))
            .map(|width_hz| width_hz.abs())
            .filter(|width_hz| width_hz.is_finite() && *width_hz > 0.0)
            .sum::<f64>();
        let native_width_hz = (native_width_hz > 0.0)
            .then_some(native_width_hz)
            .or(spectral_delta_hz);
        let rest_frequency_hz = selected
            .frequencies_hz
            .first()
            .zip(selected.frequencies_hz.last())
            .map(|(first, last)| 0.5 * (*first + *last));
        return Ok(SinglePlaneCubeCoordinateMetadata {
            spectral_delta_hz: native_width_hz,
            rest_frequency_hz,
            ..Default::default()
        });
    }

    let (channel_start, channel_count) = shared_single_plane_channel_window(config)?;
    let selected = resolve_contiguous_channel_selection(
        &table_values.spw_freqs_hz,
        channel_start,
        channel_count,
    )
    .map_err(|error| error.to_string())?;
    if selected.indices.len() != 1 || selected.frequencies_hz.len() != 1 {
        return Err(format!(
            "cubedata one-channel metadata expected one selected channel, resolved {}",
            selected.indices.len()
        ));
    }
    let channel_index = selected.indices[0];
    let native_width_hz = table_values
        .spw_widths_hz
        .get(channel_index)
        .copied()
        .map(f64::abs)
        .filter(|width| width.is_finite() && *width > 0.0)
        .or(spectral_delta_hz);
    let rest_frequency_hz = table_values
        .spw_freqs_hz
        .first()
        .zip(table_values.spw_freqs_hz.last())
        .map(|(first, last)| 0.5 * (*first + *last));

    Ok(SinglePlaneCubeCoordinateMetadata {
        coordinate_freq_ref: Some(table_values.freq_ref),
        channel_frequencies_hz: Some(selected.frequencies_hz),
        spectral_delta_hz: native_width_hz,
        rest_frequency_hz,
    })
}

fn cube_one_channel_briggs_density_weight(
    row: &MsImagingDensityEssentials,
    polarization: CubeOneChannelBriggsPolarization,
    source_channel_indices: &[usize],
    contributions: &[CubeChannelContribution],
) -> Result<Option<f32>, String> {
    let mut explicit_weight = 0.0f32;
    let mut first_weight = 0.0f32;
    let mut second_weight = 0.0f32;
    for contribution in contributions {
        if !(contribution.factor.is_finite() && contribution.factor > 0.0) {
            return Ok(None);
        }
        let Some(&source_channel) = source_channel_indices.get(contribution.source_channel) else {
            return Ok(None);
        };
        let local_channel =
            local_channel_index(source_channel, row.channel_origin, row.channel_count)?;
        match polarization {
            CubeOneChannelBriggsPolarization::Explicit { corr_index, .. } => {
                if *row.flag.get((corr_index, local_channel)).ok_or_else(|| {
                    format!("FLAG index [{corr_index}, {source_channel}] out of bounds")
                })? {
                    return Ok(None);
                }
                let weight = row_weight_for_corr_channel(row, corr_index, local_channel)?;
                if !(weight.is_finite() && weight > 0.0) {
                    return Ok(None);
                }
                explicit_weight += weight * contribution.factor;
            }
            CubeOneChannelBriggsPolarization::CollapsedPair {
                first_corr_index,
                second_corr_index,
                ..
            } => {
                if *row
                    .flag
                    .get((first_corr_index, local_channel))
                    .ok_or_else(|| {
                        format!("FLAG index [{first_corr_index}, {source_channel}] out of bounds")
                    })?
                    || *row
                        .flag
                        .get((second_corr_index, local_channel))
                        .ok_or_else(|| {
                            format!(
                                "FLAG index [{second_corr_index}, {source_channel}] out of bounds"
                            )
                        })?
                {
                    return Ok(None);
                }
                let first = row_weight_for_corr_channel(row, first_corr_index, local_channel)?;
                let second = row_weight_for_corr_channel(row, second_corr_index, local_channel)?;
                if !(first.is_finite() && first > 0.0 && second.is_finite() && second > 0.0) {
                    return Ok(None);
                }
                first_weight += first * contribution.factor;
                second_weight += second * contribution.factor;
            }
        }
    }
    let weight = match polarization {
        CubeOneChannelBriggsPolarization::Explicit { .. } => explicit_weight,
        CubeOneChannelBriggsPolarization::CollapsedPair { .. } => first_weight + second_weight,
    };
    (weight.is_finite() && weight > 0.0)
        .then_some(weight)
        .ok_or_else(|| "invalid cube Briggs density weight".to_string())
        .map(Some)
}

fn row_weight_for_corr_channel(
    row: &MsImagingDensityEssentials,
    corr_index: usize,
    local_channel: usize,
) -> Result<f32, String> {
    if let Some(weight_spectrum) = &row.weight_spectrum {
        weight_spectrum
            .get((corr_index, local_channel))
            .copied()
            .ok_or_else(|| {
                format!("WEIGHT_SPECTRUM index [{corr_index}, {local_channel}] out of bounds")
            })
    } else {
        row.weight
            .get(corr_index)
            .copied()
            .ok_or_else(|| format!("WEIGHT correlation {corr_index} out of bounds"))
    }
}

fn routed_row_natural_weight_for_source_slot(
    row: &StandardMfsVisibilityRow,
    source_slot: usize,
) -> Result<f32, String> {
    let source_channel = *row
        .source_channel_indices
        .get(source_slot)
        .ok_or_else(|| format!("routed row source slot {source_slot} is out of bounds"))?;
    let local_channel = source_channel
        .checked_sub(row.channel_origin)
        .ok_or_else(|| {
            format!(
                "routed source channel {source_channel} precedes loaded origin {}",
                row.channel_origin
            )
        })?;
    match row.polarization {
        StandardMfsVisibilityPolarization::Explicit { corr_index, .. } => {
            if let Some(weight_spectrum) = &row.weight_spectrum {
                weight_spectrum
                    .get((corr_index, local_channel))
                    .copied()
                    .ok_or_else(|| {
                        format!(
                            "routed WEIGHT_SPECTRUM index [{corr_index}, {local_channel}] out of bounds"
                        )
                    })
            } else {
                row.weight
                    .get(corr_index)
                    .copied()
                    .ok_or_else(|| format!("routed WEIGHT correlation {corr_index} out of bounds"))
            }
        }
        StandardMfsVisibilityPolarization::CollapsedPair {
            first_corr_index,
            second_corr_index,
            ..
        } => {
            let (first, second) = if let Some(weight_spectrum) = &row.weight_spectrum {
                (
                    weight_spectrum
                        .get((first_corr_index, local_channel))
                        .copied()
                        .ok_or_else(|| {
                            format!(
                                "routed WEIGHT_SPECTRUM index [{first_corr_index}, {local_channel}] out of bounds"
                            )
                        })?,
                    weight_spectrum
                        .get((second_corr_index, local_channel))
                        .copied()
                        .ok_or_else(|| {
                            format!(
                                "routed WEIGHT_SPECTRUM index [{second_corr_index}, {local_channel}] out of bounds"
                            )
                        })?,
                )
            } else {
                (
                    row.weight.get(first_corr_index).copied().ok_or_else(|| {
                        format!("routed WEIGHT correlation {first_corr_index} out of bounds")
                    })?,
                    row.weight.get(second_corr_index).copied().ok_or_else(|| {
                        format!("routed WEIGHT correlation {second_corr_index} out of bounds")
                    })?,
                )
            };
            Ok(0.5 * (first + second))
        }
    }
}

fn preweighted_routed_row_with_weight_spectrum(
    row: &StandardMfsVisibilityRow,
    preweighted_spectrum: Array2<f32>,
) -> StandardMfsVisibilityRow {
    let corr_count = row
        .data
        .shape()
        .first()
        .copied()
        .unwrap_or(row.weight.len());
    let weights = vec![0.0f32; corr_count.max(row.weight.len())];
    StandardMfsVisibilityRow {
        uvw_m: row.uvw_m,
        spw_id: row.spw_id,
        channel_origin: row.channel_origin,
        source_channel_indices: Arc::clone(&row.source_channel_indices),
        channel_lambda_scales: Arc::clone(&row.channel_lambda_scales),
        data: row.data.clone(),
        flag: row.flag.clone(),
        weight: Arc::from(weights.into_boxed_slice()),
        weight_spectrum: Some(preweighted_spectrum),
        gridable: row.gridable,
        polarization: row.polarization,
    }
}

fn selected_channel_read_range_for_standard_mfs(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
) -> Result<Option<SelectedChannelReadRange>, String> {
    let explicit_channel_selector = selected_spw_channel_selector(config, table_values.spw_id)?;
    let source_channel_selection = match explicit_channel_selector.as_ref() {
        Some(selector) => resolve_channel_selector_selection(&table_values.spw_freqs_hz, selector)
            .map_err(|error| error.to_string())?,
        None => {
            let (channel_start, channel_count) = shared_single_plane_channel_window(config)?;
            resolve_contiguous_channel_selection(
                &table_values.spw_freqs_hz,
                channel_start,
                channel_count,
            )
            .map_err(|error| error.to_string())?
        }
    };
    let Some(&start) = source_channel_selection.indices.first() else {
        return Ok(None);
    };
    if source_channel_selection
        .indices
        .iter()
        .enumerate()
        .all(|(offset, &channel)| channel == start + offset)
    {
        Ok(Some(SelectedChannelReadRange {
            start,
            count: source_channel_selection.indices.len(),
        }))
    } else {
        Ok(None)
    }
}

fn shared_single_plane_channel_window(
    config: &CliConfig,
) -> Result<(Option<usize>, Option<usize>), String> {
    let cube_like_single_plane =
        standard_cube_like_one_channel_can_use_mfs_single_plane_path(config)
            || mosaic_cube_one_channel_can_use_single_plane_stream(config);
    let channel_start = if cube_like_single_plane {
        match config.cube_axis.start {
            Some(CubeAxisValue::Channel(channel)) if channel < 0 => {
                return Err(format!(
                    "cube channel start {channel} is negative; channel-mode start must be >= 0"
                ));
            }
            Some(CubeAxisValue::Channel(channel)) => Some(channel as usize),
            _ => config.channel_start,
        }
    } else {
        config.channel_start
    };
    let channel_count = if cube_like_single_plane {
        match config.cube_axis.width {
            Some(CubeAxisValue::Channel(0)) => {
                return Err("cube channel width must not be zero".to_string());
            }
            Some(CubeAxisValue::Channel(width)) => Some(width.unsigned_abs() as usize),
            _ => config.channel_count,
        }
    } else {
        config.channel_count
    };
    Ok((channel_start, channel_count))
}

fn selected_channel_read_range_for_shared_single_plane_acceleration(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
) -> Result<Option<SelectedChannelReadRange>, String> {
    if config.spectral_mode.is_cube_like()
        && !standard_cube_like_one_channel_can_use_mfs_single_plane_path(config)
        && !mosaic_cube_one_channel_can_use_single_plane_stream(config)
    {
        return Ok(None);
    }
    selected_channel_read_range_for_standard_mfs(config, table_values)
}

fn selected_channel_read_range_for_cube_source_row_blocks(
    config: &CliConfig,
    table_values: &PreparedSelectionTableValues,
    selection: &SelectedRowsContext,
    derived_engine: Option<&MsCalEngine>,
) -> Result<Option<SelectedChannelReadRange>, String> {
    if !config.spectral_mode.is_cube_like() {
        return selected_channel_read_range_for_standard_mfs(config, table_values);
    }
    let explicit_channel_selector = selected_spw_channel_selector(config, table_values.spw_id)?;
    if let Some(selector) = explicit_channel_selector.as_ref() {
        let source_channel_selection =
            resolve_channel_selector_selection(&table_values.spw_freqs_hz, selector)
                .map_err(|error| error.to_string())?;
        return Ok(SelectedChannelReadRange::from_contiguous_indices(
            &source_channel_selection.indices,
        ));
    }

    if let Some(range) =
        direct_nearest_cube_source_read_range(config, table_values, selection, derived_engine)?
    {
        return Ok(Some(range));
    }

    let cube_axis = cube_axis_for_config(config);
    let cube_context = cube_setup_context_for_selection(selection, derived_engine)?;
    let (_cube_setup, support_selection) = CubeSpectralSetup::for_casa_cube_axis(
        table_values.freq_ref,
        &table_values.spw_freqs_hz,
        &table_values.spw_widths_hz,
        config
            .channel_count
            .unwrap_or(table_values.spw_freqs_hz.len()),
        &cube_axis,
        cube_context.reference_row_time_mjd_sec,
        cube_context.spectral_frame_field_id,
        cube_context.phase_center_direction.clone(),
        cube_context.time_bounds_mjd_sec,
        cube_context.derived_engine,
    )
    .map_err(|error| error.to_string())?;
    Ok(SelectedChannelReadRange::from_contiguous_indices(
        &support_selection.indices,
    ))
}

fn uvw_reprojection_mode_for_selection(
    config: &CliConfig,
    selection: &SelectedRowsContext,
) -> UvwReprojectionMode {
    if config.use_pointing
        || selection.phase_center.field_id.is_none()
        || selection
            .selected_rows
            .iter()
            .any(|row| Some(row.field_id) != selection.phase_center.field_id)
    {
        UvwReprojectionMode::Mosaic
    } else {
        UvwReprojectionMode::Standard
    }
}

fn data_description_index(
    data_description: &casa_ms::subtables::data_description::MsDataDescription<'_>,
) -> Result<Vec<Option<(usize, usize)>>, String> {
    let mut index = Vec::with_capacity(data_description.row_count());
    for row in 0..data_description.row_count() {
        let spw_id = data_description
            .spectral_window_id(row)
            .map_err(|error| format!("map DDID {row} to SPW: {error}"))?;
        let polarization_id = data_description
            .polarization_id(row)
            .map_err(|error| format!("map DDID {row} to POLARIZATION: {error}"))?;
        if spw_id < 0 || polarization_id < 0 {
            index.push(None);
        } else {
            index.push(Some((spw_id as usize, polarization_id as usize)));
        }
    }
    Ok(index)
}

fn allowed_ddids(
    config: &CliConfig,
    ddid_info: &[Option<(usize, usize)>],
) -> Result<Vec<bool>, String> {
    let mut allowed = vec![true; ddid_info.len()];
    let selected_spw = selected_spw_id(config)?;
    if let Some(spw) = selected_spw {
        allowed.fill(false);
        for (ddid, info) in ddid_info.iter().enumerate() {
            if info.is_some_and(|(row_spw, _)| row_spw == spw as usize) {
                allowed[ddid] = true;
            }
        }
        if !allowed.iter().any(|value| *value) {
            return Err(format!("selection resolved to no DDID for SPW {spw}"));
        }
    }
    if let Some(ddid) = config.ddid {
        if ddid < 0 || ddid as usize >= ddid_info.len() || ddid_info[ddid as usize].is_none() {
            return Err(format!(
                "DATA_DESC_ID {ddid} is outside the DATA_DESCRIPTION table"
            ));
        }
        if let Some(spw) = selected_spw
            && ddid_info[ddid as usize].is_none_or(|(row_spw, _)| row_spw != spw as usize)
        {
            return Err(format!("DATA_DESC_ID {ddid} does not map to SPW {spw}"));
        }
    }
    Ok(allowed)
}

fn selected_spw_id(config: &CliConfig) -> Result<Option<i32>, String> {
    if let Some(selector_text) = config.spw_selector.as_deref() {
        let selectors = parse_spw_selector(selector_text).map_err(|error| error.to_string())?;
        let ids = selectors
            .iter()
            .map(|selector| selector.spw_id)
            .collect::<std::collections::BTreeSet<_>>();
        return match ids.len() {
            0 => Ok(None),
            1 => Ok(ids.into_iter().next()),
            _ => Err(format!(
                "spw selector {selector_text:?} resolved to multiple SPWs; the current frontend accepts exactly one"
            )),
        };
    }
    Ok(config.spw)
}

fn selected_spw_channel_selector(
    config: &CliConfig,
    spw_id: usize,
) -> Result<Option<casa_ms::ChannelSelection>, String> {
    let Some(selector_text) = config.spw_selector.as_deref() else {
        return Ok(None);
    };
    let selectors = parse_spw_selector(selector_text).map_err(|error| error.to_string())?;
    let Some(selector) = selectors
        .into_iter()
        .find(|selector| selector.spw_id == spw_id as i32)
    else {
        return Ok(None);
    };
    Ok(selector.channels)
}

fn selection_may_require_phase_reprojection(config: &CliConfig) -> bool {
    config.phasecenter_field.is_some()
        || config.phasecenter.is_some()
        || config
            .field_ids
            .as_ref()
            .is_none_or(|field_ids| field_ids.len() != 1)
}

fn extract_phase_center(ms: &MeasurementSet, field_id: usize) -> Result<PhaseCenter, String> {
    let field = ms.field().map_err(|error| format!("open FIELD: {error}"))?;
    if field
        .num_poly(field_id)
        .map_err(|error| format!("read FIELD.NUM_POLY: {error}"))?
        != 0
    {
        return Err(
            "moving or tracked phase centers (NUM_POLY != 0) are not supported".to_string(),
        );
    }
    let phase_dir = resolve_field_phase_direction_j2000(ms, field_id)
        .map_err(|error| format!("resolve FIELD.PHASE_DIR[{field_id}] to J2000: {error}"))?;
    let (ra, dec) = phase_dir.as_angles();
    Ok(PhaseCenter {
        field_id: Some(field_id),
        angles_rad: [ra, dec],
        reference: DirectionRef::J2000,
    })
}

fn resolve_phase_center(
    ms: &MeasurementSet,
    selected_fields: &BTreeSet<i32>,
    config: &CliConfig,
) -> Result<PhaseCenter, String> {
    let Some(first_selected) = selected_fields.iter().next().copied() else {
        return Err("selection resolved to no field".to_string());
    };
    if let Some(text) = config.phasecenter.as_deref() {
        return parse_phase_center_literal(text);
    }
    if let Some(field_id) = config.phasecenter_field {
        if !selected_fields.contains(&field_id) {
            return Err(format!(
                "phase-center FIELD_ID {field_id} is not part of the selected field set {:?}",
                selected_fields
            ));
        }
        return extract_phase_center(ms, field_id as usize);
    }
    if selected_fields.len() == 1 {
        return extract_phase_center(ms, first_selected as usize);
    }
    let reference = extract_phase_center(ms, first_selected as usize)?;
    let all_match = selected_fields.iter().copied().all(|field_id| {
        extract_phase_center(ms, field_id as usize)
            .map(|candidate| {
                candidate.reference == reference.reference
                    && (candidate.angles_rad[0] - reference.angles_rad[0]).abs() <= 1.0e-12
                    && (candidate.angles_rad[1] - reference.angles_rad[1]).abs() <= 1.0e-12
            })
            .unwrap_or(false)
    });
    if all_match {
        Ok(reference)
    } else {
        Err(format!(
            "field selection {:?} spans multiple phase centers; set --phasecenter-field",
            selected_fields
        ))
    }
}

fn parse_phase_center_literal(text: &str) -> Result<PhaseCenter, String> {
    let parts = text.split_whitespace().collect::<Vec<_>>();
    if parts.len() != 3 {
        return Err(format!(
            "phasecenter {text:?} must be 'REF lon lat', for example 'J2000 19:59:28.500 +40.44.01.50'"
        ));
    }
    let reference = parts[0]
        .parse::<DirectionRef>()
        .map_err(|error| format!("parse phasecenter reference {:?}: {error}", parts[0]))?;
    if reference != DirectionRef::J2000 {
        return Err(format!(
            "phasecenter reference {reference:?} is not supported yet; expected J2000"
        ));
    }
    let ra = parse_phase_center_angle(parts[1], true)?;
    let dec = parse_phase_center_angle(parts[2], false)?;
    Ok(PhaseCenter {
        field_id: None,
        angles_rad: [ra, dec],
        reference,
    })
}

fn parse_phase_center_angle(text: &str, longitude: bool) -> Result<f64, String> {
    let unit = Unit::new("rad").expect("rad is a valid unit");
    if let Ok(quantity) = text.parse::<Quantity>() {
        return quantity
            .get_value_in(&unit)
            .map_err(|error| format!("convert phasecenter angle {text:?} to radians: {error}"));
    }
    if !longitude {
        if let Some(value) = parse_dms_token(text) {
            return Ok(value * std::f64::consts::PI / 180.0);
        }
    }
    if let Some(value) = parse_hms_token(text) {
        if longitude {
            return Ok(value * std::f64::consts::PI / 12.0);
        }
        return Err(format!(
            "phasecenter latitude {text:?} looks like a right ascension; expected a declination"
        ));
    }
    if longitude {
        if let Some(value) = parse_dms_token(text) {
            return Ok(value * std::f64::consts::PI / 180.0);
        }
    } else if let Some(value) = parse_dms_token(text) {
        return Ok(value * std::f64::consts::PI / 180.0);
    }
    Err(format!(
        "unsupported phasecenter angle {text:?}; use a quantity like '1.2rad'/'40deg' or sexagesimal text"
    ))
}

fn parse_hms_token(text: &str) -> Option<f64> {
    let normalized = normalize_sexagesimal_token(text, true)?;
    let parts = normalized.split_whitespace().collect::<Vec<_>>();
    if parts.len() != 3 {
        return None;
    }
    let hours = parts[0].parse::<f64>().ok()?;
    let minutes = parts[1].parse::<f64>().ok()?;
    let seconds = parts[2].parse::<f64>().ok()?;
    let sign = if hours < 0.0 { -1.0 } else { 1.0 };
    Some(sign * (hours.abs() + minutes / 60.0 + seconds / 3600.0))
}

fn parse_dms_token(text: &str) -> Option<f64> {
    let normalized = normalize_sexagesimal_token(text, false)?;
    let parts = normalized.split_whitespace().collect::<Vec<_>>();
    if parts.len() != 3 {
        return None;
    }
    let degrees = parts[0].parse::<f64>().ok()?;
    let minutes = parts[1].parse::<f64>().ok()?;
    let seconds = parts[2].parse::<f64>().ok()?;
    let sign = if degrees < 0.0 { -1.0 } else { 1.0 };
    Some(sign * (degrees.abs() + minutes / 60.0 + seconds / 3600.0))
}

fn normalize_sexagesimal_token(text: &str, hour_style: bool) -> Option<String> {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return None;
    }
    let sign = if trimmed.starts_with('-') {
        "-"
    } else if trimmed.starts_with('+') {
        "+"
    } else {
        ""
    };
    let body = trimmed.trim_start_matches(['+', '-']);
    let split_by = if body.contains(':') {
        Some(body.split(':').map(str::to_string).collect::<Vec<_>>())
    } else if body.contains('h') || body.contains('d') || body.contains('m') || body.contains('s') {
        let normalized = body
            .replace(['h', 'd', 'm', 's'], " ")
            .split_whitespace()
            .map(str::to_string)
            .collect::<Vec<_>>();
        Some(normalized)
    } else if !hour_style && body.matches('.').count() >= 2 {
        let mut parts = body.split('.').map(str::to_string).collect::<Vec<_>>();
        let tail = parts.split_off(2);
        let mut normalized = parts;
        normalized.push(tail.join("."));
        Some(normalized)
    } else {
        None
    }?;
    if split_by.len() != 3 {
        return None;
    }
    let mut normalized = split_by;
    normalized[0] = format!("{sign}{}", normalized[0]);
    Some(normalized.join(" "))
}

fn resolve_data_column(
    ms: &MeasurementSet,
    explicit: Option<&str>,
) -> Result<VisibilityDataColumn, String> {
    if let Some(name) = explicit {
        return parse_data_column(name);
    }
    if ms.data_column(VisibilityDataColumn::CorrectedData).is_ok() {
        Ok(VisibilityDataColumn::CorrectedData)
    } else if ms.data_column(VisibilityDataColumn::Data).is_ok() {
        Ok(VisibilityDataColumn::Data)
    } else {
        Err("MS has neither CORRECTED_DATA nor DATA".to_string())
    }
}

fn parse_data_column(name: &str) -> Result<VisibilityDataColumn, String> {
    match name.to_ascii_uppercase().as_str() {
        "DATA" => Ok(VisibilityDataColumn::Data),
        "CORRECTED_DATA" | "CORRECTED" => Ok(VisibilityDataColumn::CorrectedData),
        "MODEL_DATA" | "MODEL" => Ok(VisibilityDataColumn::ModelData),
        _ => Err(format!("unsupported data column {name:?}")),
    }
}

fn parse_save_model_mode(name: &str) -> Result<SaveModelMode, String> {
    match name.to_ascii_lowercase().replace(['_', '-'], "").as_str() {
        "none" => Ok(SaveModelMode::None),
        "modelcolumn" => Ok(SaveModelMode::ModelColumn),
        _ => Err(format!(
            "unsupported savemodel value {name:?}; expected none or modelcolumn"
        )),
    }
}

fn parse_single_numeric_selector(value: &str, label: &str) -> Result<i32, String> {
    let parsed = parse_numeric_id_selector(value, label).map_err(|error| error.to_string())?;
    match parsed.as_slice() {
        [single] => Ok(*single),
        [] => Err(format!("{label} selector {value:?} resolved to no ids")),
        _ => Err(format!(
            "{label} selector {value:?} resolved to multiple ids; the current frontend accepts exactly one"
        )),
    }
}

fn parse_numeric_selector(value: &str, label: &str) -> Result<Vec<i32>, String> {
    let ids = parse_numeric_id_selector(value, label).map_err(|error| error.to_string())?;
    if ids.is_empty() {
        Err(format!("{label} selector {value:?} resolved to no ids"))
    } else {
        Ok(ids)
    }
}

fn parse_cube_axis_value(text: &str, veltype: DopplerRef) -> Result<CubeAxisValue, String> {
    CubeAxisValue::parse(text, veltype).map_err(|error| error.to_string())
}

fn parse_cube_interpolation(text: &str) -> Result<CubeInterpolation, String> {
    match text.trim().to_ascii_lowercase().as_str() {
        "nearest" => Ok(CubeInterpolation::Nearest),
        "linear" => Ok(CubeInterpolation::Linear),
        "cubic" => Err(
            "unsupported cube interpolation \"cubic\"; cubic is not implemented yet".to_string(),
        ),
        other => Err(format!("unsupported cube interpolation {other:?}")),
    }
}

fn parse_rest_frequency_hz(text: &str) -> Result<f64, String> {
    parse_ms_rest_frequency_hz(text).map_err(|error| error.to_string())
}

