    struct EnvGuard {
        name: &'static str,
        previous: Option<std::ffi::OsString>,
    }

    impl EnvGuard {
        fn set(name: &'static str, value: &str) -> Self {
            let previous = env::var_os(name);
            unsafe {
                env::set_var(name, value);
            }
            Self { name, previous }
        }

        fn unset(name: &'static str) -> Self {
            let previous = env::var_os(name);
            unsafe {
                env::remove_var(name);
            }
            Self { name, previous }
        }
    }

    impl Drop for EnvGuard {
        fn drop(&mut self) {
            unsafe {
                if let Some(previous) = &self.previous {
                    env::set_var(self.name, previous);
                } else {
                    env::remove_var(self.name);
                }
            }
        }
    }

    #[test]
    fn read_columnar_prepared_source_uses_visibility_buffer_and_geometry_rows() {
        let mut ms = MeasurementSet::create_memory(
            MeasurementSetBuilder::new()
                .with_main_column(OptionalMainColumn::Data)
                .with_main_column(OptionalMainColumn::WeightSpectrum),
        )
        .unwrap();
        add_vla_antenna_pair(&mut ms);
        add_field_row(&mut ms);
        add_observation_row(&mut ms);
        add_spectral_window_row(&mut ms, &[1.0e9, 1.1e9, 1.2e9, 1.3e9]);
        add_polarization_row(&mut ms);
        add_data_description_row(&mut ms);
        add_main_row_with_field_and_antennas_channels_and_weight_spectrum(
            &mut ms,
            0,
            0,
            1,
            [10.0, 20.0, 30.0],
            &[
                Complex32::new(0.0, 0.0),
                Complex32::new(1.0, -1.0),
                Complex32::new(2.0, -2.0),
                Complex32::new(3.0, -3.0),
                Complex32::new(10.0, -10.0),
                Complex32::new(11.0, -11.0),
                Complex32::new(12.0, -12.0),
                Complex32::new(13.0, -13.0),
            ],
            &[1.0, 2.0, 3.0, 4.0, 10.0, 20.0, 30.0, 40.0],
        );
        add_main_row_with_field_and_antennas_channels_and_weight_spectrum(
            &mut ms,
            0,
            0,
            1,
            [110.0, 120.0, 130.0],
            &[
                Complex32::new(100.0, -100.0),
                Complex32::new(101.0, -101.0),
                Complex32::new(102.0, -102.0),
                Complex32::new(103.0, -103.0),
                Complex32::new(110.0, -110.0),
                Complex32::new(111.0, -111.0),
                Complex32::new(112.0, -112.0),
                Complex32::new(113.0, -113.0),
            ],
            &[101.0, 102.0, 103.0, 104.0, 201.0, 202.0, 203.0, 204.0],
        );
        ms.main_table_mut()
            .column_accessor_mut("FLAG_ROW")
            .unwrap()
            .set_scalar_assuming_valid(1, ScalarValue::Bool(true))
            .unwrap();

        let config = CliConfig::parse([
            OsString::from("--ms"),
            OsString::from("example.ms"),
            OsString::from("--imagename"),
            OsString::from("target/example"),
            OsString::from("--imsize"),
            OsString::from("64"),
            OsString::from("--cell-arcsec"),
            OsString::from("1.0"),
            OsString::from("--spw"),
            OsString::from("0"),
            OsString::from("--phasecenter-field"),
            OsString::from("0"),
            OsString::from("--gridder"),
            OsString::from("standard"),
        ])
        .unwrap();
        let data_description = ms.data_description().unwrap();
        let ddid_info = data_description_index(&data_description).unwrap();
        let spectral_window = ms.spectral_window().unwrap();
        let polarization = ms.polarization().unwrap();
        let selection = select_main_rows(&ms, &config, &ddid_info).unwrap();
        let table_values = load_prepared_selection_table_values(
            selection.selected_ddid,
            &ddid_info,
            &spectral_window,
            &polarization,
        )
        .unwrap();
        let geometry_columns = PreparedGeometryColumnCache::load(&ms, config.use_pointing).unwrap();
        let reversed_rows = vec![
            selection.selected_rows[1].clone(),
            selection.selected_rows[0].clone(),
        ];
        let source = read_columnar_prepared_source(
            &ms,
            VisibilityDataColumn::Data,
            true,
            &selection,
            &table_values,
            &ddid_info,
            &reversed_rows,
            None,
            uvw_reprojection_mode_for_selection(&config, &selection),
            Some(SelectedChannelReadRange { start: 1, count: 2 }),
            &geometry_columns,
            None,
            None,
        )
        .unwrap();
        let view = source.source_view().unwrap();

        assert_eq!(source.geometry_rows.len(), 2);
        assert_eq!(
            source
                .geometry_rows
                .iter()
                .map(|row| row.selected_row.row_index)
                .collect::<Vec<_>>(),
            vec![1, 0]
        );
        assert!(source.visibility.uvw.is_none());
        assert_eq!(source.fill_report.channel_start, 1);
        assert_eq!(source.fill_report.channel_count, 2);
        assert_eq!(view.row_count(), 2);
        assert_eq!(view.partition.shape.channel_count, 4);
        assert_eq!(view.partition.shape.correlation_count, 2);
        assert_eq!(view.channel_range(), 1..3);
        assert_eq!(view.flag_row, None);
        assert_eq!(view.time, None);
        let row_one_data = source.data_2d(0).unwrap();
        let row_zero_data = source.data_2d(1).unwrap();
        assert_eq!(
            row_one_data.get_local(0, row_one_data.local_channel(1).unwrap(), 1),
            Ok(Complex32::new(101.0, -101.0))
        );
        assert_eq!(
            row_one_data.get_local(1, row_one_data.local_channel(2).unwrap(), 2),
            Ok(Complex32::new(112.0, -112.0))
        );
        assert_eq!(
            row_zero_data.get_local(0, row_zero_data.local_channel(1).unwrap(), 1),
            Ok(Complex32::new(1.0, -1.0))
        );
        assert_eq!(
            row_zero_data.get_local(1, row_zero_data.local_channel(2).unwrap(), 2),
            Ok(Complex32::new(12.0, -12.0))
        );
        let row_one_weights = source.weights(0).unwrap();
        let row_zero_weights = source.weights(1).unwrap();
        assert_eq!(
            row_one_weights.get_local(0, 0),
            Ok((102.0, WeightSourceKind::WeightSpectrum))
        );
        assert_eq!(
            row_one_weights.get_local(1, 1),
            Ok((203.0, WeightSourceKind::WeightSpectrum))
        );
        assert_eq!(
            row_zero_weights.get_local(0, 0),
            Ok((2.0, WeightSourceKind::WeightSpectrum))
        );
        assert_eq!(
            row_zero_weights.get_local(1, 1),
            Ok((30.0, WeightSourceKind::WeightSpectrum))
        );
        assert!(source.flag_row_value(&selection.flag_row, 0, 1).unwrap());
        assert!(!source.flag_row_value(&selection.flag_row, 1, 0).unwrap());
        let density_source = read_columnar_prepared_source(
            &ms,
            VisibilityDataColumn::Data,
            false,
            &selection,
            &table_values,
            &ddid_info,
            &reversed_rows,
            None,
            uvw_reprojection_mode_for_selection(&config, &selection),
            Some(SelectedChannelReadRange { start: 1, count: 2 }),
            &geometry_columns,
            None,
            None,
        )
        .unwrap();
        assert!(!density_source.has_visibility_data());
        assert!(density_source.data_2d(0).is_err());
        assert!(
            !density_source
                .flags_2d(0)
                .unwrap()
                .get_local(0, 0, 1)
                .unwrap()
        );
        assert_eq!(
            density_source.weights(0).unwrap().get_local(1, 1),
            Ok((203.0, WeightSourceKind::WeightSpectrum))
        );
        let Some(VisibilityFloatSamplesRef::Float32(weight_spectrum)) = view.weight_spectrum else {
            panic!("expected Float32 WEIGHT_SPECTRUM");
        };
        assert_eq!(
            weight_spectrum,
            &[102.0, 202.0, 2.0, 20.0, 103.0, 203.0, 3.0, 30.0]
        );

        let cache_key = visibility_geometry_cache_key_for_rows(
            &config,
            &selection,
            &table_values,
            &reversed_rows,
            Some(SelectedChannelReadRange { start: 1, count: 2 }),
            spectral_slab::ImagingPassKind::InitialDirty,
        );
        let mut geometry_cache = VisibilityGeometryCache::new(true, 1024 * 1024);
        let cached_first = read_columnar_prepared_source(
            &ms,
            VisibilityDataColumn::Data,
            true,
            &selection,
            &table_values,
            &ddid_info,
            &reversed_rows,
            None,
            uvw_reprojection_mode_for_selection(&config, &selection),
            Some(SelectedChannelReadRange { start: 1, count: 2 }),
            &geometry_columns,
            Some(&mut geometry_cache),
            Some(cache_key.clone()),
        )
        .unwrap();
        let cached_second = read_columnar_prepared_source(
            &ms,
            VisibilityDataColumn::Data,
            true,
            &selection,
            &table_values,
            &ddid_info,
            &reversed_rows,
            None,
            uvw_reprojection_mode_for_selection(&config, &selection),
            Some(SelectedChannelReadRange { start: 1, count: 2 }),
            &geometry_columns,
            Some(&mut geometry_cache),
            Some(cache_key),
        )
        .unwrap();
        assert_eq!(
            cached_first.geometry_cache_lookup,
            Some(VisibilityGeometryCacheLookup {
                hit: false,
                stored: true,
                estimated_bytes: estimated_geometry_rows_bytes(&cached_first.geometry_rows),
            })
        );
        assert_eq!(
            cached_second.geometry_cache_lookup,
            Some(VisibilityGeometryCacheLookup {
                hit: true,
                stored: true,
                estimated_bytes: estimated_geometry_rows_bytes(&cached_second.geometry_rows),
            })
        );
        assert!(Arc::ptr_eq(
            &cached_first.geometry_rows,
            &cached_second.geometry_rows
        ));
        assert_eq!(
            source.geometry_rows[0].trace(),
            cached_second.geometry_rows[0].trace()
        );
        assert_eq!(
            source.geometry_rows[1].trace(),
            cached_second.geometry_rows[1].trace()
        );
        let cached_view = cached_second.source_view().unwrap();
        let Some(VisibilityFloatSamplesRef::Float32(cached_weight_spectrum)) =
            cached_view.weight_spectrum
        else {
            panic!("expected cached Float32 WEIGHT_SPECTRUM");
        };
        assert_eq!(cached_weight_spectrum, weight_spectrum);
        let cache_stats = geometry_cache.stats();
        assert_eq!(1, cache_stats.fills);
        assert_eq!(1, cache_stats.hits);
        assert_eq!(1, cache_stats.shares);
    }

    #[test]
    fn standard_mfs_runtime_plan_guard_restores_previous_environment() {
        let runtime_env_lock = STANDARD_MFS_RUNTIME_ENV_LOCK
            .lock()
            .expect("standard MFS runtime env lock");
        let _test_env = EnvGuard::set("CASA_RS_STANDARD_MFS_TEST_RESTORE", "before");

        {
            let mut plan = StandardMfsRuntimePlanGuard::new(runtime_env_lock);
            plan.set("CASA_RS_STANDARD_MFS_TEST_RESTORE", "during");
            assert_eq!(
                env::var("CASA_RS_STANDARD_MFS_TEST_RESTORE").as_deref(),
                Ok("during")
            );
        }

        assert_eq!(
            env::var("CASA_RS_STANDARD_MFS_TEST_RESTORE").as_deref(),
            Ok("before")
        );
    }

    fn diagnostic_padded_len(image_len: usize, padding_factor: f64) -> usize {
        let padded = (padding_factor * image_len as f64 - 0.5).floor() as usize;
        let padded = padded.max(image_len);
        if padded % 2 == 0 { padded } else { padded + 1 }
    }

    fn read_full_f32_image(path: impl AsRef<Path>) -> ArrayD<f32> {
        let image = PagedImage::<f32>::open(path.as_ref()).unwrap();
        image
            .get_slice(&vec![0; image.shape().len()], image.shape())
            .unwrap()
    }

    fn assert_f32_images_close(lhs_path: impl AsRef<Path>, rhs_path: impl AsRef<Path>, tol: f32) {
        let lhs = read_full_f32_image(lhs_path.as_ref());
        let rhs = read_full_f32_image(rhs_path.as_ref());
        assert_eq!(lhs.shape(), rhs.shape());
        let mut max_abs_diff = 0.0f32;
        for (lhs, rhs) in lhs.iter().zip(rhs.iter()) {
            max_abs_diff = max_abs_diff.max((*lhs - *rhs).abs());
        }
        assert!(
            max_abs_diff <= tol,
            "image products differ: max_abs_diff={max_abs_diff} tol={tol} lhs={} rhs={}",
            lhs_path.as_ref().display(),
            rhs_path.as_ref().display()
        );
    }

