    #[test]
    fn weight_spectrum_takes_precedence_over_weight() {
        let weight_row =
            ArrayValue::Float32(ArrayD::from_shape_vec(vec![2], vec![1.0f32, 2.0]).unwrap());
        let weight_spectrum =
            ArrayValue::Float32(ArrayD::from_shape_vec(vec![2, 1], vec![3.0f32, 4.0]).unwrap());
        let (weight, source) =
            resolve_weight_with_source(&weight_row, Some(&weight_spectrum), 1, 0).unwrap();
        assert_eq!(weight, 4.0);
        assert_eq!(source, WeightSourceKind::WeightSpectrum);
    }

    #[test]
    fn selected_weight_spectrum_missing_cells_fall_back_to_weight() {
        let column = SelectedMainArrayColumn {
            column_name: "WEIGHT_SPECTRUM",
            values: vec![None],
            channel_origin: 0,
        };
        assert_eq!(column.get_optional(0).unwrap(), None);
        assert!(
            column
                .get_optional(1)
                .unwrap_err()
                .contains("out of bounds")
        );

        let weight_row =
            ArrayValue::Float32(ArrayD::from_shape_vec(vec![2], vec![1.0f32, 2.0]).unwrap());
        let (weight, source) = resolve_weight_with_source(&weight_row, None, 1, 0).unwrap();
        assert_eq!(weight, 2.0);
        assert_eq!(source, WeightSourceKind::Weight);
    }

    #[test]
    fn cube_briggs_preweighting_preserves_multi_source_slot_rows() {
        let selected_row = SelectedMainRow {
            row_index: 0,
            field_id: 3,
            ddid: 0,
            spw_id: 0,
            polarization_id: 0,
            time_mjd_seconds: Some(12.5),
        };
        let spectral = Arc::new(CubeRowSpectralContributions {
            output_channel_contributions: Vec::new(),
            source_channel_output_map: vec![Some(0), Some(0)],
            padded_source_channel_output_map: vec![Some(0), Some(1)],
            padded_grid_channel_contributions: Vec::new(),
            grid_channel_contributions: Vec::new(),
            source_channel_model_contributions: Vec::new(),
        });
        let mut row_spectral_cache = HashMap::new();
        row_spectral_cache.insert(
            (
                selected_row.time_mjd_seconds.unwrap().to_bits(),
                selected_row.field_id,
            ),
            spectral,
        );
        let mut density0 = Array2::<f32>::zeros((16, 16));
        let mut density1 = Array2::<f32>::zeros((16, 16));
        let center =
            casa_cube_briggs_density_cell_from_lambda(density0.dim(), 0.0, 0.0, [1.0, 1.0])
                .unwrap();
        density0[center] = 2.0;
        density1[center] = 7.0;
        let plan = CubeOneChannelBriggsStreamingPlanWithGeometry {
            geometry: ImageGeometry {
                image_shape: [16, 16],
                cell_size_rad: [1.0, 1.0],
            },
            plan: CubeOneChannelBriggsStreamingPlan {
                cube_setup: CubeSpectralSetup {
                    source_freq_ref: FrequencyRef::TOPO,
                    output_freq_ref: FrequencyRef::TOPO,
                    interpolation: CubeInterpolation::Nearest,
                    interpolation_uses_native_source_frequencies: true,
                    output_frame_reference_time_mjd_sec: 12.5,
                    output_frame_field_id: 3,
                    output_channel_frequencies_hz: vec![1.0],
                    output_channel_widths_hz: vec![1.0],
                },
                source_channel_indices: Arc::from([0usize, 1usize]),
                source_channel_frequencies_hz: Arc::from([1.0_f64, 2.0_f64]),
                source_channel_widths_hz: Arc::from([1.0_f64, 1.0_f64]),
                row_spectral_cache,
                density_grids: vec![density0, density1],
                f2_by_plane: vec![1.0, 1.0],
                weighting: WeightingMode::Uniform,
                fractional_bandwidth: 0.0,
                polarization: CubeOneChannelBriggsPolarization::CollapsedPair {
                    first_corr_index: 0,
                    second_corr_index: 1,
                },
            },
        };
        let row = StandardMfsVisibilityRow {
            uvw_m: [0.0, 0.0, 0.0],
            spw_id: 0,
            channel_origin: 0,
            source_channel_indices: Arc::from([0usize, 1usize]),
            channel_lambda_scales: Arc::from([1.0_f64, 2.0_f64]),
            data: Array2::from_shape_vec(
                (2, 2),
                vec![
                    Complex32::new(1.0, 0.0),
                    Complex32::new(2.0, 0.0),
                    Complex32::new(3.0, 0.0),
                    Complex32::new(4.0, 0.0),
                ],
            )
            .unwrap(),
            flag: Array2::from_shape_vec((2, 2), vec![false, false, false, false]).unwrap(),
            weight: Arc::from([99.0_f32, 99.0_f32]),
            weight_spectrum: Some(
                Array2::from_shape_vec((2, 2), vec![2.0_f32, 4.0, 6.0, 10.0]).unwrap(),
            ),
            gridable: true,
            polarization: StandardMfsVisibilityPolarization::CollapsedPair {
                first_corr_index: 0,
                second_corr_index: 1,
                transform: StandardMfsPairCollapseTransform::HalfSum,
                sumwt_factor: 2.0,
            },
        };

        let preweighted = plan
            .preweighted_row_for_target_readonly(&selected_row, &row, None)
            .unwrap();
        assert_eq!(preweighted.source_channel_indices.as_ref(), &[0, 1]);
        assert_eq!(preweighted.channel_lambda_scales.as_ref(), &[1.0, 2.0]);
        assert!(preweighted.weight.iter().all(|value| *value == 0.0));
        let spectrum = preweighted
            .weight_spectrum
            .as_ref()
            .expect("expected per-source-slot preweighted spectrum");
        assert!((spectrum[(0, 0)] - 2.0).abs() < 1.0e-6);
        assert!((spectrum[(1, 0)] - 2.0).abs() < 1.0e-6);
        assert!((spectrum[(0, 1)] - 1.0).abs() < 1.0e-6);
        assert!((spectrum[(1, 1)] - 1.0).abs() < 1.0e-6);
    }

    #[test]
    fn explicit_cube_linear_interpolation_drops_when_any_contributor_is_flagged() {
        let data_values = [Complex32::new(1.0, 0.0), Complex32::new(3.0, 0.0)];
        let flag_values = [false, true];
        let weight_values = [2.0f32];
        let data = ComplexRow2d::Complex32Columnar {
            values: &data_values,
            row_slot: 0,
            row_count: 1,
            corr_count: 1,
            channels: 2,
            channel_origin: 0,
        };
        let flags = BoolRow2d::Columnar {
            values: &flag_values,
            row_slot: 0,
            row_count: 1,
            corr_count: 1,
            channels: 2,
            channel_origin: 0,
        };
        let weights = WeightRow {
            weights: FloatRow1d::Float32Columnar {
                values: &weight_values,
                row_slot: 0,
                corr_count: 1,
            },
            spectrum: None,
        };
        let contributions = vec![
            CubeChannelContribution {
                source_channel: 0,
                source_frequency_hz: 1.0,
                factor: 0.25,
            },
            CubeChannelContribution {
                source_channel: 1,
                source_frequency_hz: 2.0,
                factor: 0.75,
            },
        ];

        let sample = interpolate_explicit_cube_output_sample_from_rows(
            &data,
            &flags,
            &weights,
            0,
            &[0, 1],
            0.0,
            1.75,
            &contributions,
            false,
        )
        .unwrap();
        assert!(
            sample.is_none(),
            "expected CASA-style linear interpolation to discard the whole output sample when any contributing source channel is flagged"
        );
    }

    #[test]
    fn explicit_cube_linear_interpolation_aggregates_visibility_and_weight() {
        let data_values = [Complex32::new(1.0, 2.0), Complex32::new(5.0, 6.0)];
        let flag_values = [false, false];
        let weight_values = [4.0f32];
        let weight_spectrum_values = [2.0f32, 10.0];
        let data = ComplexRow2d::Complex32Columnar {
            values: &data_values,
            row_slot: 0,
            row_count: 1,
            corr_count: 1,
            channels: 2,
            channel_origin: 0,
        };
        let flags = BoolRow2d::Columnar {
            values: &flag_values,
            row_slot: 0,
            row_count: 1,
            corr_count: 1,
            channels: 2,
            channel_origin: 0,
        };
        let weights = WeightRow {
            weights: FloatRow1d::Float32Columnar {
                values: &weight_values,
                row_slot: 0,
                corr_count: 1,
            },
            spectrum: Some(FloatRow2d::Float32Columnar {
                values: &weight_spectrum_values,
                row_slot: 0,
                row_count: 1,
                corr_count: 1,
                channels: 2,
                channel_origin: 0,
            }),
        };
        let contributions = vec![
            CubeChannelContribution {
                source_channel: 0,
                source_frequency_hz: 1.0,
                factor: 0.25,
            },
            CubeChannelContribution {
                source_channel: 1,
                source_frequency_hz: 2.0,
                factor: 0.75,
            },
        ];

        let sample = interpolate_explicit_cube_output_sample_from_rows(
            &data,
            &flags,
            &weights,
            0,
            &[0, 1],
            0.0,
            1.75,
            &contributions,
            false,
        )
        .unwrap()
        .expect("expected interpolated sample");
        assert!((sample.visibility.re - 4.0).abs() < 1.0e-6);
        assert!((sample.visibility.im - 5.0).abs() < 1.0e-6);
        assert!((sample.weight - 8.0).abs() < 1.0e-6);
        assert!((sample.sumwt_factor - 1.0).abs() < 1.0e-6);
    }

    #[test]
    fn paired_cube_linear_interpolation_drops_when_any_hand_contributor_is_flagged() {
        let data = ArrayValue::Complex32(
            ArrayD::from_shape_vec(
                vec![2, 2],
                vec![
                    Complex32::new(1.0, 0.0),
                    Complex32::new(3.0, 0.0),
                    Complex32::new(2.0, 0.0),
                    Complex32::new(4.0, 0.0),
                ],
            )
            .unwrap(),
        );
        let flags = ArrayValue::Bool(
            ArrayD::from_shape_vec(vec![2, 2], vec![false, false, false, true]).unwrap(),
        );
        let weights =
            ArrayValue::Float32(ArrayD::from_shape_vec(vec![2], vec![1.0f32, 1.0]).unwrap());
        let contributions = vec![
            CubeChannelContribution {
                source_channel: 0,
                source_frequency_hz: 1.0,
                factor: 0.5,
            },
            CubeChannelContribution {
                source_channel: 1,
                source_frequency_hz: 2.0,
                factor: 0.5,
            },
        ];

        let sample = interpolate_paired_cube_output_sample(
            &data,
            &flags,
            &weights,
            None,
            (0, 1),
            &[0, 1],
            0.0,
            1.5,
            &contributions,
            false,
        )
        .unwrap();
        assert!(
            sample.is_none(),
            "expected strict Stokes-I linear interpolation to discard the output sample when either contributing hand is flagged"
        );
    }

    #[test]
    fn dynamic_phase_reference_is_converted_to_j2000() {
        let tmp = tempdir().unwrap();
        let ms_path = tmp.path().join("dynamic_phase.ms");
        let mut ms = MeasurementSet::create(
            &ms_path,
            MeasurementSetBuilder::new().with_main_column(OptionalMainColumn::Data),
        )
        .unwrap();
        add_vla_antenna_row(&mut ms);
        let time_mjd_sec = 59_000.5 * 86_400.0;
        let j2000 = MDirection::from_angles(1.0, 0.5, DirectionRef::J2000);
        let frame = MeasFrame::new()
            .with_epoch(MEpoch::from_mjd(time_mjd_sec / 86_400.0, EpochRef::UTC))
            .with_position(MPosition::new_itrf(VLA_X, VLA_Y, VLA_Z))
            .with_bundled_eop();
        let azel = j2000.convert_to(DirectionRef::AZEL, &frame).unwrap();
        add_field_row_with_direction(&mut ms, azel, time_mjd_sec);
        let field_table = ms.subtable_mut(SubtableId::Field).unwrap();
        TableMeasDesc::new_fixed("PHASE_DIR", MeasureType::Direction, "AZEL")
            .write(field_table)
            .unwrap();
        ms.save().unwrap();

        let phase_center = extract_phase_center(&ms, 0).unwrap();
        assert_eq!(phase_center.reference, DirectionRef::J2000);
        assert!((phase_center.angles_rad[0] - 1.0).abs() < 1e-9);
        assert!((phase_center.angles_rad[1] - 0.5).abs() < 1e-9);
    }

